		var collisionWalk = navigateCamera(direction);

		if (!collisionWalk){
			direction.applyQuaternion( this.vrcamera.quaternion );
			currCamPos.add(direction.multiplyScalar(stereoSpeedScale)); // go in specified direction if collision walking does not work.
		}
