function CloseTutorial() {
	if (boxTarget !== undefined)
		boxTarget.style.display = 'none';
	if (boxTarget2 !== undefined)
		boxTarget2.style.display = 'none';
	bFirstTimeVisitingFP = false;
	bFirstTimeVisitingStereo = false;
}

function DoTutorial() {
	boxTarget = document.getElementById('startupTutorial');
	boxTargetTxt = document.getElementById('startupTutorialPrmpt');
	if (mobileAndTabletcheck())
		boxTargetTxt.innerHTML = resources["#tut_mes_2"];
	else
		boxTargetTxt.innerHTML = resources["#tut_mes_3"];
	boxTarget2 = document.getElementById('contextualTutorial');
	boxTarget2Txt = document.getElementById('contextualTutorialPrmpt');
	if(mobileAndTabletcheck())
		boxTarget2Txt.innerHTML = resources["#tut_mes_14"];
	else
		boxTarget2Txt.innerHTML = resources["#tut_mes_13"];
	var xComp = window.innerWidth;
	var yComp = window.innerHeight;
	/*
	if (mobileAndTabletcheck() && window.orientation % 180 != 0) { // if in landscape
		xComp = window.innerHeight;
		yComp = window.innerWidth;
	}
	*/

	var decodedCookie = decodeURIComponent(document.cookie);
	if (decodedCookie == "") {
		bFirstTimeVisitingFP = true;
		bFirstTimeVisitingStereo = true;
		boxTarget.style.display = 'block';
		document.cookie = "username=default; path=/";
	}
	else{
		boxTarget.style.display = 'none';
		boxTarget2.style.display = 'none';
	}

	$("#closePrmpt").css({ "display": "block" });

	boxPos = {x: window.innerWidth/2, y: window.innerHeight/2, rotation: 0};
	// first movement
	firstTween = new TWEEN.Tween(boxPos)
		.to({x: xComp/2, y: (yComp/2) - 50, rotation: 0}, 2000)
		.easing(TWEEN.Easing.Elastic.InOut);

	// second movement
	secondTween = new TWEEN.Tween(boxPos)
		.to({x: xComp-200, y: yComp-200, rotation: 0}, 2000)
		.easing(TWEEN.Easing.Elastic.InOut);

	// third movement
	thirdTween = new TWEEN.Tween(boxPos)
		.to({x: xComp-200, y: 100, rotation: 0}, 2000)
		.easing(TWEEN.Easing.Elastic.InOut);

	// fourth movement
	fourTween = new TWEEN.Tween(boxPos)
		.to({x: 50, y: yComp-200, rotation: 0}, 2000)
		.easing(TWEEN.Easing.Elastic.InOut);

	contextTween = new TWEEN.Tween(boxPos)
		.to({x: xComp/3, y: (yComp/3), rotation: 0}, 500)
		.easing(TWEEN.Easing.Elastic.InOut);

	currTween = firstTween;

	currTween.start();
}

 /*
    This method switches the clip cube button and its some of its attributes (visibility, etc.).

    config parameters:
    isCCOn - force the interactive clip planes to be on/off.
    isBtnVis - force the interactive CC button to be visible/invisible.
    doReset - reset the clipping planes within the model.
 */
 function switchInteractiveClipCube(config) {
    if (manager._clipSimulation !== undefined){
        interactiveCCSwitch = config !== undefined ? config.isCCOn : !interactiveCCSwitch;
        var cubeOffImgUrl = window.Configuration.withStaticPrefix('cubeOff.png');
        var cubeOnImgUrl = window.Configuration.withStaticPrefix('cubeOn.png');
        var img = interactiveCCSwitch ? "transparent url(" + cubeOnImgUrl + ")" : "transparent url(" + cubeOffImgUrl + " )";
        $("#clipCubeBtn").css({"background" : img});
        manager._clipSimulation.setSelectionMeshVisibility(interactiveCCSwitch);
    }

    if (config !== undefined){
        var btnVisStr = config.isBtnVis !== undefined && config.isBtnVis === true ? "inline" : "none";
        $("#clipCubeBtn").css({"display" : btnVisStr}); // make button visible/invisible
        if (config.doReset)
            manager._clipSimulation.resetPlanes();
    }
}

function fpcDis() {
    bAreFPCen = controlsFRC.enabled;
    if (bAreFPCen) {
        controlsFRC.enabled = false;
        document.addEventListener("mouseup", fpcEn);
        document.addEventListener("touchend", fpcEn);
    }
}

function fpcEn() {
    if (bAreFPCen) {
        controlsFRC.enabled = true;
        bAreFPCen = false;
        document.removeEventListener("mouseup", fpcEn);
        document.removeEventListener("touchend", fpcEn);
    }
}

function replaceWithImgStr(inMainStr, inDelimiter, inImgStr){
	var outStr = inMainStr.replace(inDelimiter, inImgStr);
	return outStr;
}

function setMetricSetting () {
    var IsInMetricStr = resources["#Other Options App"]["FP Settings"]["isMetric"];
    if (IsInMetricStr && IsInMetricStr.indexOf("true") > -1)
        bIsInMetric = true;
    else
        bIsInMetric = false;
}

