	function ShowPopup(inText){
		$("#helpTxt").css({ "display": "block" });
        if (mobileAndTabletcheck())
            $("#helpTxt").css({ "font-size": "100%", "color" : "black" });
		$("#helpTxt").text(inText);
        $("#helpTxt").css({
            "display": "inline"
        });
        $("#myModal").modal("toggle");
	}

    // Written by AGorbaty
    function tswc() {
        if (!(mobileAndTabletcheck()))
        	ShowPopup(resources["#360ErrorMessage"]);
    }

    function setAboutString(hours, minutes, seconds) {
        $("#helpTxt")[0].innerHTML = "";
        if (window.location.href.indexOf("https://vgx.vectorworks.net") > -1) {
            $("#helpTxt")[0].innerHTML += resources["#infoStrings"]["exTime"];
            $("#helpTxt")[0].innerHTML += hours + resources["#infoStrings"]["hrs"] + minutes + resources["#infoStrings"]["mins"] + seconds + resources["#infoStrings"]["secs"];
            $("#helpTxt")[0].innerHTML += "<br/>";
        }
        $("#helpTxt")[0].innerHTML += resources["#infoStrings"]["faces"];
        $("#helpTxt")[0].innerHTML += Math.floor(manager._modelInfo.numberOfTriangles);
        $("#helpTxt")[0].innerHTML += "<br/>";
        $("#helpTxt")[0].innerHTML += resources["#infoStrings"]["geoms"];
        $("#helpTxt")[0].innerHTML += renderer.info.memory.geometries;
        $("#helpTxt")[0].innerHTML += "<br/>";
        $("#helpTxt")[0].innerHTML += resources["#infoStrings"]["texts"];
        $("#helpTxt")[0].innerHTML += renderer.info.memory.textures;
    }

    function timeLeft() {
        var element = document.querySelector('meta[property="uploadTime"]');
        if (element != null) {
			var futureTime = new Date(element.getAttribute("data-uploadTime"));
	        var currTime = new Date();
	        futureTime.setDate(futureTime.getDate() + 14);
	        var resultTime = futureTime - currTime;
	        var seconds = Math.floor(resultTime / 1000);
	        var minutes = Math.floor(seconds / 60);
	        var hours = Math.floor(minutes / 60);
	        var convMinutes = minutes % 60;
	        var convSeconds = seconds % 60;
	        setAboutString(hours, convMinutes, convSeconds);
        }
        else
        	setAboutString(-1, -1, -1);
    }

    function displayAbout() {
        $("#orbitNavHelp").css({ "display": "none" });
        $("#firstNavHelp").css({ "display": "none" });
        $("#monoStereoHelp").css({ "display": "none" });
        timeLeft();
        $("#modalContext").css({
            background: "transparent url('')",
            "background-repeat": "no-repeat",
            "background-size": "100% 100%"
        });
        $("#helpTxt").css({ "display": "block" });
        fpcDis();
        if (mobileAndTabletcheck())
            $("#helpTxt").css({ "font-size": "100%", "color" : "black" });
        $("#myModal").modal("toggle");
        lftTmr = setInterval(timeLeft, 1000);
        $("#myModal").on("hidden.bs.modal", function () {
            clearInterval(lftTmr);
            fpcEn();
        });
    }

