    // Written by ProtoTech, categorized by AGorbaty
    function progInit() {
        var h = 50;
        var e = renderer.domElement;
        var f = h / (Math.tan(camera.fov / 2) * 350);
        var j = f * (e.height / (2 * window.devicePixelRatio));
        $("#svg #bar").attr("r", Math.abs(j));
        $("#svg #barInner").attr("r", Math.abs(j));
        $("#svg #bar").attr("stroke-dasharray", Math.abs(Math.PI * 2 * j));
        $("#svg #barInner").attr("stroke-dasharray", Math.abs(Math.PI * 2 * j));
        $("#svg #bar").attr("stroke-dashoffset", Math.abs(Math.PI * 2 * j));
    }

