    // Written by AGorbaty
    function skipProgressRender() {
        var bCannotIncrementBar = (menuMesh.children[0].id == previousId && isSelected == 1) || (menuMesh.children[1].id == previousId && isSelected == 0);
        if (bCannotIncrementBar) {
            document.getElementById("bar").removeEventListener("transitionend", transEnd, false);
            $("#svg #bar").css({ visibility: "hidden" });
            $("#svg #barInner").css({ visibility: "hidden" });
        }
        else {
            document.getElementById("bar").addEventListener("transitionend", transEnd, false);
            $("#svg #bar").css({ visibility: "visible" });
            $("#svg #barInner").css({ visibility: "visible" });
        }
        return bCannotIncrementBar;
    }
    function setNextToClosestObjectAsIntersection(){
    	if (gIntersections.length == 2)
    		gIntersections[0].object.visible = false;
    	else if (gIntersections.length > 2) {
    		gIntersections[0].object.visible = false;
    		gIntersections[1].object.visible = false;
    	}
      renderer.animate(animate);
      manager._renderAdaptor.render();

    }

    function resetGlobalIntersections(inRaycaster) {
		var octreeObjects = [];
        for(var tx = 0 ; tx < manager._octreeList.length; tx++ ){
            var octObj = manager._octreeList[tx].search( inRaycaster.ray.origin, 40000000, true, inRaycaster.ray.direction );
            for(var tx1 = 0 ; tx1 < octObj.length; tx1++ ){
                octreeObjects.push(octObj[tx1]);
            }
        }
        gIntersections = inRaycaster.intersectOctreeObjects(octreeObjects);
        gIntersections.sort(function(a,b){return a.distance - b.distance});
    }




    // Written by ProtoTech, categorized by AGorbaty
    function jumpToFirstPlaceOnGeometry(inStartPosition) {
		renderer.animate(animate);
    	var modified = false;
		if(!manager._modelInfo.navigationMeshCreated){
			ShowPopup(resources["#notdone"]);
			return modified;
		}
        var camPos = new THREE.Vector3();
        for (var tx1 = 0 ; tx1 < gIntersections.length; tx1++) {
            if (gIntersections[tx1].object.material.opacity < 1 && tx1 != (gIntersections.length - 1))
                continue;
            else if (!gIntersections[tx1].object.visible)
                continue;
            else if (gIntersections[tx1].face.normal.z.toFixed(5) <= 0.00) {
                modified = true;
                var newRayPt = new THREE.Vector3();
                newRayPt.copy(gIntersections[tx1].point);
                var newRaYPtDir = new THREE.Vector3();
                newRaYPtDir.copy(camera.getWorldDirection());
                if (gIntersections[tx1].face.normal.z.toFixed(5) < 0.00)
                    newRayPt.sub(newRaYPtDir.multiplyScalar(10));
                else
                    newRayPt.sub(newRaYPtDir.multiplyScalar(1500));

                var flRayCast = new THREE.Raycaster(newRayPt, new THREE.Vector3(0, -1, 0), 0, 40000000);

                var octreeObjects = [];
                for (var tx = 0 ; tx < manager._octreeList.length; tx++) {
                    var octObj = manager._octreeList[tx].search(flRayCast.ray.origin, 40000000, true, flRayCast.ray.direction);
                    for (var tx1 = 0 ; tx1 < octObj.length; tx1++) {
                        octreeObjects.push(octObj[tx1]);
                    }
                }
                var hrIntersects = flRayCast.intersectOctreeObjects(octreeObjects);
                if (hrIntersects.length > 0) {
                    hrIntersects.sort(function (a, b) { return a.distance - b.distance });
                    camPos.copy(hrIntersects[0].point);
                }
                else
                    return;
                break;
            }
            else {
                modified = true;
                camPos.copy(gIntersections[tx1].point);
                break;
            }
        }
        for (var i = 0 ; i < scene.children.length; i++) {
            for (var j = 0 ; j < scene.children[i].children.length; j++) {
                for (var k = 0 ; k < scene.children[i].children[j].children.length; k++) {
                    scene.children[i].children[j].children[k].visible = true;
                }
            }
        }
        for (var j = 0; j < gIntersections.length; j++)
        	gIntersections[j].object.visible = true;
        if (!modified)
            return modified;
        if (tweenTime >= 500) {
        	var tweenAnim = new TWEEN.Tween( inStartPosition ).to( {x: camPos.x,y: camPos.y+controlsFRC.personHeight ,z: camPos.z}, tweenTime ).easing( TWEEN.Easing.Quadratic.In).start();
      tweenQueue.push(tweenAnim);
			manager._renderAdaptor.render = manager._renderAdaptor.setRender(manager._renderAdaptor._normalRenderer);
			manager._renderAdaptor._cameraMoving = true;
			tweenAnim.onComplete(function(){
				manager._renderAdaptor.render = manager._renderAdaptor.setRender(manager._renderAdaptor._composerRenderer);
				manager._renderAdaptor._cameraMoving = false;
				manager._renderAdaptor.render();
        tweenQueue.pop();
        if (tweenQueue.length == 0)
          renderer.animate(null);
			});
        	if (tweenTime != 500)
        		tweenTime -= 500;
        }
        controlsFRC.object.position.copy(camPos);
        controlsFRC.object.position.add(new THREE.Vector3(0, controlsFRC.personHeight, 0));
        return modified;
    }

    // initiailization and animate

    function update()
    {
        switch(controltype)
        {
            case 1: {
                controlsORC.update();
                camera.lookAt(controlsORC.target);
								break;
            }
            case 2: controlsFRC.update(); break;
            case 3: {
                        if (controlsDRC)
                            controlsDRC.update();
                        else
                            controlsVR.update(stereoCamVector);
                        break;
            }
            default: controlsORC.update(); break;
        }

        if (boxPos !== undefined) {
	        boxTarget.style.left = boxPos.x + 'px';
			boxTarget.style.top = boxPos.y + 'px';
			boxTarget.style.webkitTransform = 'rotate(' + Math.floor(boxPos.rotation) + 'deg)';
			boxTarget.style.MozTransform = 'rotate(' + Math.floor(boxPos.rotation) + 'deg)';
			if (updateCount <= 1800) {
				if (updateCount == 300) {
					TWEEN.remove(currTween);
					currTween = secondTween;
					if (mobileAndTabletcheck())
						boxTargetTxt.innerHTML = resources["#tut_mes_5"];
					else
						boxTargetTxt.innerHTML = resources["#tut_mes_4"];
					boxTargetTxt.innerHTML = replaceWithImgStr(boxTargetTxt.innerHTML,'[eyeButton]', "<img width='26' height='26' src='https://vgx.vectorworks.net/WebApp1.9.3/ControllerIcon.png'>");
					currTween.start();
				}
				else if (updateCount == 600 && mobileAndTabletcheck()){
					boxTargetTxt.innerHTML = resources["#tut_mes_6"];
					boxTargetTxt.innerHTML = replaceWithImgStr(boxTargetTxt.innerHTML,'[360Button]', "<img width='26' height='26' src='https://vgx.vectorworks.net/WebApp1.9.3/360.png'>");
				}
				else if (updateCount == 900) {
					TWEEN.remove(currTween);
					currTween = thirdTween;
					if (mobileAndTabletcheck())
						boxTargetTxt.innerHTML = resources["#tut_mes_8"];
					else
						boxTargetTxt.innerHTML = resources["#tut_mes_7"];
					boxTargetTxt.innerHTML = replaceWithImgStr(boxTargetTxt.innerHTML,'[optButton]', "<img width='26' height='26' src='https://vgx.vectorworks.net/WebApp1.9.3/settings.png'>");
					currTween.start();
				}
				else if (updateCount == 1200) {
					if (mobileAndTabletcheck())
						boxTargetTxt.innerHTML = resources["#tut_mes_10"];
					else
						boxTargetTxt.innerHTML = resources["#tut_mes_9"];
					boxTargetTxt.innerHTML = replaceWithImgStr(boxTargetTxt.innerHTML,'[homeButton]', "<img width='26' height='26' src='https://vgx.vectorworks.net/WebApp1.9.3/home.png'>");
				}
				else if (updateCount == 1500) {
					TWEEN.remove(currTween);
					currTween = fourTween;
					if (mobileAndTabletcheck())
						boxTargetTxt.innerHTML = resources["#tut_mes_12"];
					else
						boxTargetTxt.innerHTML = resources["#tut_mes_11"];
					boxTargetTxt.innerHTML = replaceWithImgStr(boxTargetTxt.innerHTML,'[helpButton]', "<img width='26' height='26' src='https://vgx.vectorworks.net/WebApp1.9.3/help.png'>");
					currTween.start();
				}
				else if (updateCount == 1800) {
					TWEEN.remove(currTween);
					boxTarget.style.display = 'none';
				}
				updateCount++
			}
		}
    }

	function onDocumentFocus(){
		onWindowResize();
		window.removeEventListener('focus', onDocumentFocus);
    renderer.animate(animate);
	}

	/*window.onDocumentBlur = function() {
		window.addEventListener('focus', onDocumentFocus);
		renderer.animate(null);
	}

	window.addEventListener('blur', onDocumentBlur);*/

	function onWindowResize() {
		renderer.setSize(window.innerWidth - 1,window.innerHeight - 1);
		setTimeout(function(){
			(manager._renderAdaptor._normalRenderer.windowResize())();
			(manager._renderAdaptor._composerRenderer.windowResize())();

            if (stereoeffect !== undefined)
                stereoeffect.setSize(window.innerWidth - 1,window.innerHeight - 1);

			var canvas = renderer.domElement;
			var wrad = 25;

			var intradPix = wrad/(Math.tan(camera.fov/2) * 350)
			var radPix = intradPix * (canvas.height / (2 * window.devicePixelRatio));
			$('#svg #bar').attr("r",Math.abs(radPix));
			$('#svg #barInner').attr("r",Math.abs(radPix));
			$('#svg #bar').attr("stroke-dasharray",Math.abs(Math.PI*2*radPix));
			$('#svg #barInner').attr("stroke-dasharray",Math.abs(Math.PI*2*radPix) );
			$('#svg #bar').attr("stroke-dashoffset",Math.abs(Math.PI*2*radPix) );
			render();
		},500);
    }

	function render() {
		bIsCollisionOn = $('#collisionbox').is(':checked');
		TWEEN.update();
		light.position.copy(camera.position);
		// Following switch case is to be removed. The check in this render loop is not good.
		// We should create an interface and keep on switching the object it uses for rendering the scene.
		switch (controltype){
			case 3:{
                    if (!bUsingPolyfill){
                        stereoCamWrapper.position.copy(camera.position);
                        if (HMDName.indexOf('OpenVR') != -1 || HMDName.indexOf('Oculus') != -1)
                            stereoCamWrapper.position.multiplyScalar(1000);
                        stereoCamWrapper.position.add(stereoCamVector);
                    }
                    else
                        camera.position.copy(stereoCamVector);

                    light.position.multiplyScalar(1000);
                    light.position.add(stereoCamVector);

                    if(bUsingPolyfill)
                        stereoeffect.render(scene, camera);
                    else
                        renderer.render( scene, camera );

                    if (HMDName.indexOf('OpenVR') == -1 && HMDName.indexOf('Oculus') == -1 && HMDName.indexOf('Daydream') == -1)
                        menuRelatedSettings(bUsingPolyfill);

                    switch(currentAction)
                    {
                        case 0:
                            navigateCamera();
                        break;
                        case 1:  break;
                        default: break;

                    }
                    break;
            }
			case 2:
			case 1:
			default:
				manager._renderAdaptor.render();
			break;
		}
	}


    function animate() {
	    render();
	    update();
	};

