// Main VGX service. Only contains reading methods at the moment. Will implement dynamic scene changes in the near future.
var VGX = function(inVersion){
	console.log("VGX Initialized!");
	if (inVersion === undefined)
		this.g_VGXVersion = 0.2;
	else
		this.g_VGXVersion = inVersion;
};

//Returns a promise of the object containing all the 
var promiseTexture = function(textureFiles, textureMap){
	return new Promise(function(resolve){
		var promiseArray = [];
		textureFiles.forEach(function(textureFile){
			promise = textureFile.async('base64');
			promiseArray.push(promise);
			promise.then(function(content){
				if(content)
					textureMap[textureFile.name] = "data:image/png;base64," + content;
			},function(e){
				console.log(e);
			});
		});
		Promise.all(promiseArray).then(function(values){
			resolve(textureMap);
		});
	});
};

var createMaterialMap = function(materialFile, textureMap, inVGXReader, bStreamsOnly){
	return new Promise(function(resolve){
		if(materialFile == null || !bStreamsOnly)
			resolve(null);
		materialFile.async('string').then(function(content){
			materialMap = getMaterialsArray2(content,textureMap,inVGXReader);
			resolve(materialMap);
		},function(e){
			console.log(e);
		});
	});
};

var getVersion = function (versionFile){
	return new Promise(function(resolve){
		if (versionFile==null){
			resolve(true);
		}
		else{
			bReadOldFile = false;
			versionFile.async('string').then(function(content){
				IVGXReader.prototype.FileVersion(content.substring(0,content.length-1));
				resolve(bReadOldFile);
			}, function(e){
				console.log(e);
			});
		}
	});
};

var createInstanceObject = function (instanceFile){
	return new Promise(function(resolve){
		instanceFile.async('string').then(function(content){
			instObj	= JSON.parse(content.substring(0,content.length-1));
			resolve(instObj);
		}, function(e){
			console.log(e);
		});
	});
};

function startVGX(inFilePath, inVGXReader, inObjectsProcess, inOptions) {
	var textureMap = new Object();
	var version = inOptions.fVersion;
	var http = new XMLHttpRequest();
	http.open("GET",inFilePath);
	http.responseType = "arraybuffer";

	if (inOptions.fProgress !== undefined)
		http.onprogress = inOptions.fProgress;
	http.onload = function() {
		var arrayBuffer = http.response;
		if(arrayBuffer) {
			JSZip.loadAsync(arrayBuffer).then(function (zip) {
				textureFiles = zip.file(/.+\.png/);
				promiseTexture(textureFiles, textureMap).then(function(textureMap){
					var materialFile = zip.file(".vwmaterials");
					createMaterialMap(materialFile, textureMap, inVGXReader, inOptions.fbStreamsOnly).then(function(materialMap){
						var versionFile = zip.file(".version");
						getVersion(versionFile).then(function(bReadOldFile) {							
							var instanceFile = zip.file(".vwinstances");
							if(instanceFile!=null && !bReadOldFile){
								createInstanceObject(instanceFile).then(function(instObj){
									var scenegraphFile = zip.file(".vwscenegraph");
									scenegraphFile.async('string').then(function(content){
										readObjects2Mod(inVGXReader, instObj, content);
									},function(e){
										console.log(e);
									});
								});
							}
							else if(instanceFile==null && !inOptions.fbStreamsOnly){
								var sceneFile = zip.file(".vwscene");
								if(sceneFile!=null){
									version = parseFloat(sceneFile.comment.slice(sceneFile.comment.length-3,sceneFile.comment.length));
									sceneFile.async('string').then(function(content){										
										if (version > 0.2)
											readObjects3(materialMap, inVGXReader, content); // not officially availible yet
										else
											readObjects2(materialMap, inVGXReader, inObjectsProcess, content);
									},function(e){
										console.log(e);
									});
								}
							}		
						});
					});
				});

				var camerasFile = zip.file(".vwcameras");
				if(camerasFile!=null && inOptions.fbReadAll){
					readCameras2(inVGXReader, function (inText) {
						var data = JSON.parse(inText.substring(0,inText.length-1));
						inVGXReader.prototype.ReadCamera(data);
					}, camerasFile);
				}

				var customFile = zip.file(".vwcustom");
				if(customFile!=null  && (inOptions.fbStreamsOnly || inOptions.fbReadAll)){
					readStreams2(inVGXReader, customFile);
				}
			});
		}
	};
	http.send();
	return;
}

VGX.prototype.ReadFile = function(inFilePath, inVGXReader){
	if (!(inVGXReader.prototype.constructor === IVGXReader)) {
		console.log("VGX cannot read files unless you implement the IVGXReader class in your code.");
	}
	else {
		if (this.g_VGXVersion >= 0.2)
		{
			startVGX(inFilePath, inVGXReader, {fbGetNumObjects : false, fNumObjects : 1}, {fbReadAll : true, fbStreamsOnly : false, fVersion : this.g_VGXVersion})
		}
		else
		{
			// always assumes local reading for unzipped files.
			var materialMap = getMaterialsArray(inFilePath.replace(".vgx",".vwmaterials"));
			readObjects(materialMap, inVGXReader, inFilePath.replace(".vgx",".vwscene"), {fbGetNumObjects : false, fNumObjects : 1});
			readCameras(inVGXReader, inFilePath.replace(".vgx",".vwcameras"), function (inText) {
				var data = JSON.parse(inText);
				inVGXReader.prototype.ReadCamera(data);
			});
			readStreams(inVGXReader, inFilePath.replace(".vgx",".vwcustom"));
		}
	}
};

VGX.prototype.ReadFileWithProgress = function(inFilePath, inVGXReader, inProgressCallback, inReadStandardFile){
	if (!(inVGXReader.prototype.constructor === IVGXReader)) {
		console.log("VGX cannot read files unless you implement the IVGXReader class in your code.");
	}
	else {
		if (this.g_VGXVersion >= 0.2)
		{
			if(inReadStandardFile === undefined)
				startVGX(inFilePath, inVGXReader, {fbGetNumObjects : false, fNumObjects : 1}, {fbReadAll : true, fbStreamsOnly : false, fProgress : inProgressCallback, fVersion : this.g_VGXVersion});
			else
				startVGX(inFilePath, inVGXReader, {fbGetNumObjects : false, fNumObjects : 1}, {fbReadAll : true, fbStreamsOnly : false, fProgress : inProgressCallback, fVersion : this.g_VGXVersion, fReadOldFile : inReadStandardFile});
		}
		else
		{
			// don't do anything if not 0.2...
		}
	}
};


VGX.prototype.ReadObjectsFromFile = function(inFilePath, inVGXReader, inNumObjects){
	if (!(inVGXReader.prototype.constructor === IVGXReader)) {
		console.log("VGX cannot read files unless you implement the IVGXReader class in your code.");
	}
	else {
		if (this.g_VGXVersion >= 0.2)
		{
			if (inNumObjects < 1)
				startVGX(inFilePath, inVGXReader, {fbGetNumObjects : true, fNumObjects : inNumObjects}, {fbReadAll : false, fbStreamsOnly : false, fVersion : this.g_VGXVersion});
			else
				startVGX(inFilePath, inVGXReader, {fbGetNumObjects : false, fNumObjects : 1}, {fbReadAll : false, fbStreamsOnly : false, fVersion : this.g_VGXVersion});
		}
		else
		{
			var materialMap = getMaterialsArray(inFilePath.replace(".vgx",".vwmaterials"));
			if (inNumObjects < 1)
				readObjects(materialMap, inVGXReader, inFilePath.replace(".vgx",".vwscene"), {fbGetNumObjects : false, fNumObjects : 1});
			else
				readObjects(materialMap, inVGXReader, inFilePath.replace(".vgx",".vwscene"), {fbGetNumObjects : true, fNumObjects : inNumObjects});
		}
	}
};

VGX.prototype.ReadStreamsFromFile = function(inFilePath, inVGXReader){
	if (!(inVGXReader.prototype.constructor === IVGXReader)) {
		console.log("VGX cannot read files unless you implement the IVGXReader class in your code.");
	}
	else {
		if (this.g_VGXVersion >= 0.2)
		{
			startVGX(inFilePath, inVGXReader, {fbGetNumObjects : true, fNumObjects : inNumObjects}, {fbReadAll : false, fbStreamsOnly : true, fVersion : this.g_VGXVersion});
		}
		else
		{
			readStreams(inVGXReader, inFilePath.replace(".vgx",".vwcustom"));
		}
	}
};

/*
	VWModelLoader
	The VW model loader loads the raw geometry data provided by the user.
	Created By :
*/
"use strict";
var fileVersions = {
	VW2018SP3 : 0,
	VW2020 : 1,
	UnknownVersion : -1
};

self.VWModelLoader = function(manager) {
	var _requestQueue = [];
	var _freeWorkers = [];
	var _occupiedWorkers = [];

	this._manager = manager;
	this._VGXReader = Object.create(IVGXReader);
	this._matData = null;
	this._texData = null;
	this._objectInfo = new Object();
	this._firstTime = true;
	this._numPatterns = 0;
	this._numGradients = 0;
	this._numNones = 0;
	this._numHatches = 0;
	this._bIsWhiteModel = false;

	this._numObjects = 0;
	this._currObject = 0;
	this._webViewFileVersion = fileVersions.UnknownVersion;


	var barWidth = 0.1;
	var self = this;
	this._VGXReader.prototype.ReadObjects = function(inObjects, inTransforms){
		$("#myProgress").css({display:'none'});
		if (Object.keys(inObjects).length > 0){
			for (var key in inObjects)
				self.postMessageToWorker({type:'newObject2', objectData :inObjects[key], transformData :inTransforms, layerName : key});
		}
		else{
			$('#startupTutorial').css({display:'none'});
			var noticeStr = "There are no visible objects in the model. In the Vectorworks file, set the class and layer visibilities as needed, and export the model again.";
			if (resources["#helpStrings"]["helpSmInfo4"] !== undefined)
				noticeStr = resources["#helpStrings"]["helpSmInfo4"];
			ShowPopup(noticeStr);
		}
	};

	this._VGXReader.prototype.ReadObject = function(inObject) {
		$("#myProgress").css({display:'none'});
		self.postMessageToWorker({type:'newObject', objectData :inObject});
	};

	// TODO: use inObject here. inObject will not be used at this point. Only using it as a trigger to turn on shadows for now.
	this._VGXReader.prototype.ReadLight = function(inObject) {
		return;
	}

	this._VGXReader.prototype.ReadCamera = function(inCamera){

		var fov = 2*Math.atan(inCamera[0].LatBounds.w/inCamera[0].NearFar.x) * 180 / Math.PI;
		self._manager.updateCamera({
			position : [inCamera[0].eyeLoc.x,inCamera[0].eyeLoc.y,inCamera[0].eyeLoc.z],
			lookAt : [inCamera[0].CtrlLoc.x,inCamera[0].CtrlLoc.y,inCamera[0].CtrlLoc.z],
			up : [inCamera[0].UpVec.x,inCamera[0].UpVec.y,inCamera[0].UpVec.z],
			NearFar : [inCamera[0].NearFar.x,inCamera[0].NearFar.y],
			fov : fov,
			aspect : inCamera[0].aspectRatio,
			boundMin : self._boundMin,
			boundMax : self._boundMax
		});
		// set camera in the VWManager. just send JSON from here
	};

	this._VGXReader.prototype.ReadStream = function(inStream){
		  $("#myProgress").css({display:'block'});
		  var widthStr = barWidth + '%';
		  if (barWidth < 100.0){
		  	setTimeout(function() {
            $("#myBar").css({width:widthStr});
			}, 10);
		  	barWidth += 0.1; // TODO: This needs to be relocated. It's too intrusive here.
		  }

		  if (inStream.data !== undefined) {
			var data = inStream.data.split('\n');
			if (inStream.name === "clip_plane") {
				for (var i=0; i < data.length; i+=2) {
					var vertexStream = data[i].split(":");
					var dirStream = data[i+1].split(":");
					self._manager.addCuttingPlane({
						position : vertexStream[1].split(",").map(Number),
						direction : dirStream[1].split(",").map(Number)
					});
				}
			}
			else if (inStream.name === "custom_options") {
				for (var i=0; i < data.length; i++) {
					var pieceOfData = data[i].split(":");
					switch(pieceOfData[0]){
						case "ambient_size" : self._manager.addAmbientOcclusionData({
							size : parseInt(pieceOfData[1]),
						});
						break;
						case "ambient_strength" : self._manager.addAmbientOcclusionData({
							strength : parseInt(pieceOfData[1]),
						});
						break;
						case "edges_thickness" : self._manager.addEdgeShaderData({
							thickness : parseInt(pieceOfData[1]),
						});
						break;
						case "edges_crease" : self._manager.addEdgeShaderData({
							creaseAngle : parseInt(pieceOfData[1]),
						});

						break;
						case "white_model" : self._bIsWhiteModel = true;
						break;
					}
				}
			}
			else if (data.length == 5) {
				var object = {
					CN : data[0],
					Inst : 1
				};
				self._objectInfo[inStream.name]?self._objectInfo[inStream.name].push(object):self._objectInfo[inStream.name] = [object];
			}
			else if (data.length == 6) {
				var object = {
					CN : data[5],
					Inst : data[0]
				};
				self._objectInfo[inStream.name]?self._objectInfo[inStream.name].push(object):self._objectInfo[inStream.name] = [object];
			}
			else if (data.length == 7) {
				var object = {
					CN : data[0],
					LN : data[5],
					Inst : 1
				};
				self._objectInfo[inStream.name]?self._objectInfo[inStream.name].push(object):self._objectInfo[inStream.name] = [object];
			}
			else if (data.length == 8){
				var object = {
					CN : data[5],
					LN : data[7],
					Inst : data[0]
				};
				self._objectInfo[inStream.name]?self._objectInfo[inStream.name].push(object):self._objectInfo[inStream.name] = [object];
			}
			else if (inStream.name === "model_bounds"){

				if(!manager._boundMin && !manager._boundMax)
				{
					var min = new THREE.Vector3(0,0,0);
					var max = new THREE.Vector3(10000,10000,10000);
					manager._boundMin = new THREE.Vector3();
					manager._boundMax = new THREE.Vector3();
					for (var i=0; i < data.length; i++) {
					 var pieceOfData = data[i].split(":");
					 switch(pieceOfData[0]){
					  case "minVec": {
						  var vec = pieceOfData[1].split(',').map(Number);
						  min = new THREE.Vector3(vec[0],vec[1],vec[2]);
						  manager._boundMin.copy(min);
					  }
					  break;
					  case "maxVec": {
						 var vec = pieceOfData[1].split(',').map(Number);
						  max = new THREE.Vector3(vec[0],vec[1],vec[2]);
						  manager._boundMax.copy(max);
					  }
					  break;
					  default:
					  break;
					 }
					}
				}
		   }
		}

	};

	this._VGXReader.prototype.ReadMaterial = function(inMaterial,textureData){
		self._matData = inMaterial;
		self._texData = textureData;
		// Implemented and Use setter getter functions of the manager class instead of changing the objects directly.
		self._manager._modelInfo.numberOfTextures = textureData.length;

	};

	this._VGXReader.prototype.FileVersion = function(inFileVersion){
		if (inFileVersion === "2018SP3")
			this._webViewFileVersion = fileVersions.VW2018SP3;
		else if (inFileVersion === "2020")
			this._webViewFileVersion = fileVersions.VW2020;
	}

	this.init = (function(){
		return function(_maxWorker, url){
			for(var counter = 0; counter < _maxWorker; ++counter){
				var newWorker = new Worker((url)?url:"VWWorker.js");
				newWorker.id = counter + 1;
				newWorker.onmessage = this.messageFromWorker.bind(this);
				newWorker.onerror = this.messageFromWorker.bind(this);
				_freeWorkers.push(newWorker);
			}
		}
	})();

	 // The on message event is triggered by the worker class which gets the geometry data else throws an error message.
	this.postMessageToWorker = function(message,transferableArray) {
		var worker = _freeWorkers.shift();
		if(worker) {
			worker.postMessage({workerId : 1,message:message},transferableArray);
			_occupiedWorkers.push(worker);
		}
		else {
			_requestQueue.push([message,transferableArray]);
		}
	};

	this.messageFromWorker = function(event) {
		if(event.data && event.data.completed){
			for (var n = 0 ; n < _occupiedWorkers.length ; n++) {
				if (event.target.id === _occupiedWorkers[n].id) {
					var removedObject = _occupiedWorkers.splice(n,1);
					if(removedObject)
						_freeWorkers.push(removedObject[0]);
					break;
				}
			}
			if(_requestQueue.length > 0) {
				var message = _requestQueue.shift();
				this.postMessageToWorker(message[0],message[1]);
			}
			else {
				if(_occupiedWorkers.length == 0){
					for (var n = 0 ; n < _freeWorkers.length ; n++) {
						(_freeWorkers[n])?_freeWorkers[n].terminate():console.log("Error");
						_freeWorkers[n] = undefined;
					}
					 // delay octree building by 2 secs if worker ended too quickly (meaning the scene is really small).
					 // If we activate this now, the scene won't get added to the octree.
					if (this._firstTime){
						self = this;
						setTimeout(function() {
							self.dispatchEvent({type:'modelLoadiongComplete',message : event});
						}, 2000);

					}
					else
						this.dispatchEvent({type:'modelLoadiongComplete',message : event});
				}
				console.log("completed");
				this._manager._modelInfo.navigationMeshCreated = true;
			}
		}
		else
			this.onWorkerMessage(event);

	};
};


// For adding asynchronous behaviour of the application. The asynchronous behaviour is driven by the web worker here.
VWModelLoader.prototype = new THREE.EventDispatcher();

/*Set the raw geometry data to the worker for processing.*/
// Add checks for variables.
VWModelLoader.prototype.loadModel = function(message) {
	switch(message.type){
		case "addModel": {
			if(message.progressBarCallBack){
				this._manager._vgx.ReadFileWithProgress(message.file, this._VGXReader, message.progressBarCallBack, message.readStandardVGX);
			}
			else
				this._manager._vgx.ReadFile(message.file, this._VGXReader, 2);
		}
		break;
	}
}

VWModelLoader.prototype.onWorkerMessage = function(event) {

	if(event.data && event.data.success) {
		switch (event.data.type) {
			case 'geometryLoaded':
				// Hack for compensate for some browsers loading model before textures.
				if (typeof this._texData === "object" && Object.keys(this._texData).length < 3){
					self = this;
					setTimeout(function() {
						self.addGeometryToScene(event.data.processedModel);
						self.dispatchEvent({type:'objectAdded',message : "Object Added successfully to the scene"});
					}, 1000)
				}
				else{ // load object immediately
					this.addGeometryToScene(event.data.processedModel);
					this.dispatchEvent({type:'objectAdded',message : "Object Added successfully to the scene"});
				}
			break;
			case 'geometryLoaded2':
				// Hack for compensate for some browsers loading model before textures. Changed to compensate for textures that are quite large that don't load quickly.
				self = this;
				setTimeout(function() {
					self.addGeometryToScene2(event.data.processedModel);
					self.dispatchEvent({type:'objectAdded',message : "Object Added successfully to the scene"});
				}, 1000);
			break;
			default:
				var message = (event.data)?(event.data):{filename: event.filename,  lineno: event.lineno, error:event.message};
				this.dispatchEvent({type:'errorProcessing',message : message});
			break;
		}
	}
	else {
		var message = (event.data)?(event.data):{filename: event.filename,  lineno: event.lineno, error:event.message};
				this.dispatchEvent({type:'errorProcessing',message : message});
	}
}

VWModelLoader.prototype.nMatNoText = function(r,g,b,Opa,id) {
	var xxx = new THREE.Color(r,g,b);
	var mat = new THREE.MeshLambertMaterial( { color : xxx,
		opacity : Opa,
		transparent: (Opa < 1) ? true:false  ,
		side : THREE.DoubleSide,
		alphaTest : (Opa < 0.2)?0.2:0.0
	} );
	return mat;
};

VWModelLoader.prototype.nMatwText = function (r, g, b, Opa, textureData, alpha, repeatU, repeatV) {
    var mat = new THREE.MeshLambertMaterial({
        color: new THREE.Color(r, g, b),
        side: THREE.DoubleSide,
        opacity: Opa,
        transparent: (Opa < 1) ? true : false,
        shading: THREE.SmoothShading,
        alphaTest: (alpha) ? 0.1 : 0.0,
        premultipliedAlpha: true
    });
    var Im = new THREE.Texture();
    var image = new Image();
    image.src = textureData;
    image.onload = function () {
        Im.needsUpdate = true;
    };
    //var Im = THREE.ImageUtils.loadTexture(menuImage);
    Im.image = image;
    if (repeatU === undefined || repeatV === undefined) {
        Im.wrapS = THREE.RepeatWrapping;
        Im.wrapT = THREE.RepeatWrapping;
    } else {
        if (repeatU)
            Im.wrapS = THREE.RepeatWrapping;
        if (repeatV)
            Im.wrapT = THREE.RepeatWrapping;
    }
    Im.flipY = false;
    mat.map = Im;

    return mat;
}

VWModelLoader.prototype.addGeometryToScene = function(message) {
	// The below block was added the programmatically add the background + custom image if they are in the VGX file (AGorbaty)
	//this._currObject++;
	if (this._firstTime) {
		var min = rotateVectorForYUp(manager._boundMin);
		var max = rotateVectorForYUp(manager._boundMax);
		manager._boundCenter.x =  min.x + (max.x - min.x)/2.0;
		manager._boundCenter.y =  min.y + (max.y - min.y)/2.0;
		manager._boundCenter.z =  min.z + (max.z - min.z)/2.0;
		initCubeMapTexture(this._texData, min, max);
		if (this._texData['logo.png'] !== undefined)
			this._manager.setUserLogo(this._texData['logo.png']);
		this._manager.AddDefaultLight();
		this._firstTime = false;
	}

	var objectId = message.objectId.trim();
	objectId = objectId.replace(/(\r\n|\n|\r)/gm,"");
	var objectData = this._objectInfo[objectId];
	if(!objectData || message.visibility == 3)
		return;
	var layerName = objectData[message.instanceId]?(objectData[message.instanceId].LN?objectData[message.instanceId].LN:"No layer Name"):"No layer Name";
	var className = objectData[message.instanceId]?(objectData[message.instanceId].CN?objectData[message.instanceId].CN:"No class Name"):"No class Name";
	var finalGeom = message.geometry.shift();

	var layerMesh = this.getOrCreateChildNode(this._manager._scene,layerName);
	var classMesh = this.getOrCreateChildNode(layerMesh,className);

	var tm = message.transform;
	while(finalGeom) {
		var geometry = new THREE.BufferGeometry();
		geometry.addAttribute( 'position', new THREE.BufferAttribute(finalGeom.geometry.Vertices,3));
		if (finalGeom.geometry.Face) {
			geometry.setIndex( new THREE.BufferAttribute(finalGeom.geometry.Face,1));
			this._manager._modelInfo.numberOfTriangles += geometry.index.count/3;
		}
		if(finalGeom.geometry.TextureCoord) {
			geometry.addAttribute( 'uv', new THREE.BufferAttribute(finalGeom.geometry.TextureCoord,2));
		}
		if (finalGeom.meshMat.fMeshType != 5) {
			geometry.computeVertexNormals();
		}
		else{
			geometry.addAttribute('color', new THREE.BufferAttribute(finalGeom.geometry.Normal, 3));
		}

		var requiredMesh = this.getChildWithSameMaterial(classMesh,finalGeom, geometry, tm);

		var found = false;
		for(var i = 0 ; i < requiredMesh.children.length; ++i) {
			if (geometry.index != null) {

				var totalFaces = geometry.index != null ? geometry.index.count : 4294967295;
				totalFaces += requiredMesh.children[i].geometry.index != null ? requiredMesh.children[i].geometry.index.count : 4294967295;
				if(totalFaces < 4294967295) {
					requiredMesh.children[i].geometry = this.mergeGeometry(requiredMesh.children[i].geometry,geometry);
					geometry.dispose();
					found = true;
					break;
				}
			}
		}
		if(!found) {
			if(finalGeom.meshMat.fMeshType == 5){
				var points = new THREE.Points(geometry,requiredMesh.material);
				points.rotation.x = - Math.PI/2;
				points.rotation.z = Math.PI/2;
				points.updateMatrix();
				points.updateMatrixWorld();
				requiredMesh.add(points);
			}
			else if(finalGeom.meshMat.fMeshType == 1 || (finalGeom.meshMat.fMeshType == 2 && finalGeom.meshMat.fMaterialType == 7) ||
				(finalGeom.meshMat.fMeshType == 2 && finalGeom.meshMat.fMaterialType == 0 && finalGeom.flags == 64)){
				var lineMesh = new THREE.LineSegments(geometry, requiredMesh.material);
				lineMesh.rotation.x = - Math.PI/2;
				lineMesh.rotation.z = Math.PI/2;
				lineMesh.updateMatrix();
				lineMesh.updateMatrixWorld();
				requiredMesh.add(lineMesh);
			}
			else {
				var mesh = new THREE.Mesh(geometry,requiredMesh.material);
				mesh.rotation.x = - Math.PI/2;
				mesh.rotation.z = Math.PI/2;
				mesh.updateMatrix();
				mesh.updateMatrixWorld();
				requiredMesh.add(mesh);
				mesh.name = requiredMesh.name + "_" + requiredMesh.children.length;

				// create depth texture for image props shadows
				if (finalGeom.meshMat.fMaterialID != 0 && this._matData[finalGeom.meshMat.fMaterialID].hasMaskTex){
					var uniforms = THREE.ShadowAlphaShader.uniforms;
					uniforms['texture'].value = requiredMesh.material.map;

					mesh.customDepthMaterial = new THREE.MeshDepthMaterial( {

					depthPacking: THREE.RGBADepthPacking,
					map: mesh.material.map,
					side: THREE.DoubleSide,
					alphaTest: 0.2

				} );

					/*mesh.customDepthMaterial = new THREE.ShaderMaterial( {
						uniforms: uniforms,
						vertexShader: THREE.ShadowAlphaShader.vertexShader,
						fragmentShader: THREE.ShadowAlphaShader.fragmentShader,
						side: THREE.DoubleSide
					} );*/
					mesh.vgxPlant = true;
					//manager._imagePropScene.add(mesh);

				}

				if (finalGeom.meshMat.fMeshType != 2) // only put solid meshes into nav mesh
					this._manager.addToNavMesh(mesh);
			}
		}
		if (finalGeom.meshMat.fMeshType == 2 && (finalGeom.meshMat.fMaterialType == 6 || (finalGeom.meshMat.fMaterialType >= 1 && finalGeom.meshMat.fMaterialType <= 4)))
			break;
		finalGeom = message.geometry.shift();

	}
}

// alternative version to addGeometryToScene. Used with optimized web view format.
VWModelLoader.prototype.addGeometryToScene2 = function(message) {
	if (this._firstTime) {
		var min = rotateVectorForYUp(manager._boundMin);
		var max = rotateVectorForYUp(manager._boundMax);
		manager._boundCenter.x =  min.x + (max.x - min.x)/2.0;
		manager._boundCenter.y =  min.y + (max.y - min.y)/2.0;
		manager._boundCenter.z =  min.z + (max.z - min.z)/2.0;
		initCubeMapTexture(this._texData, min, max);
		if (this._texData['logo.png'] !== undefined)
			this._manager.setUserLogo(this._texData['logo.png']);
		this._manager.AddDefaultLight();
		this._firstTime = false;
	}

	var layerMesh = this.getOrCreateChildNode(this._manager._scene,message.layerName);

	var geometry = new THREE.BufferGeometry();
	geometry.addAttribute( 'position', new THREE.BufferAttribute(message.fVertices,3));
	if (message.fIndices.length > 0)
	{
		geometry.setIndex( new THREE.BufferAttribute(message.fIndices,1));
		this._manager._modelInfo.numberOfTriangles += geometry.index.count/3;
	}

	if(message.fUVs.length > 0)
		geometry.addAttribute( 'uv', new THREE.BufferAttribute(message.fUVs,2));

	if (message.fMeshType != 5)
		geometry.computeVertexNormals();
	else
		geometry.addAttribute('color', new THREE.BufferAttribute(message.fNormals, 3));

	var material = this.getChildWithSameMaterial2(message, geometry);
	if(material == undefined)
		return;
	if(message.fMeshType == 5)
	{
		var points = new THREE.Points(geometry,material);
		points.rotation.x = - Math.PI/2;
		points.rotation.z = Math.PI/2;
		points.updateMatrix();
		points.updateMatrixWorld();
		layerMesh.add(points);
	}
	else if((message.fMeshType == 0 && (message.fVertices.length/message.fIndices.length) == 2 && this._webViewFileVersion == fileVersions.VW2018SP3/*only for VW 2019 and before*/) ||
		message.fMeshType == 1 || (message.fMeshType == 2 && message.MaterialInfo.fMaterialType == 7) ||
		(message.fMeshType == 2 && message.MaterialInfo.fMaterialType == 0 && message.Flags == 64))
	{
		var lineMesh = new THREE.LineSegments(geometry,material);
		lineMesh.rotation.x = - Math.PI/2;
		lineMesh.rotation.z = Math.PI/2;
		lineMesh.updateMatrix();
		lineMesh.updateMatrixWorld();
		layerMesh.add(lineMesh);
	}
	else {
		if(message.visibility && message.visibility == 2)
		{
			material.transparent = true;
			material.opacity = 0.2;
		}
		var mesh = new THREE.Mesh(geometry,material);
		mesh.rotation.x = - Math.PI/2;
		mesh.rotation.z = Math.PI/2;
		mesh.updateMatrix();
		mesh.updateMatrixWorld();
		layerMesh.add(mesh);

		// create depth texture for image props shadows
		if (message.fMaterialID != 0) {
			var matData = this.getAppropriateMatData(message.fMaterialID);
			if (matData.hasMaskTex) {
				var uniforms = THREE.ShadowAlphaShader.uniforms;
				uniforms['texture'].value = mesh.material.map;

				mesh.customDepthMaterial = new THREE.MeshDepthMaterial( {

					depthPacking: THREE.RGBADepthPacking,
					map: mesh.material.map,
					side: THREE.DoubleSide,
					alphaTest: 0.2

				} );

				/*mesh.customDepthMaterial = new THREE.ShaderMaterial( {
					uniforms: uniforms,
					vertexShader: THREE.ShadowAlphaShader.vertexShader,
					fragmentShader: THREE.ShadowAlphaShader.fragmentShader,
					side: THREE.DoubleSide
				} );*/
				mesh.vgxPlant = true;
				//manager._imagePropScene.add(mesh);
			}
		}

		if (message.fMeshType != 2) // only put solid meshes into nav mesh
			this._manager.addToNavMesh(mesh);
	}
}

VWModelLoader.prototype.getOrCreateChildNode = function(parentNode, nodename){
	var childNode = parentNode.getObjectByName(nodename);
	if(childNode){
		return childNode;
	}
	var newChildNode = new THREE.Mesh();
	newChildNode.name = nodename;
	parentNode.add(newChildNode);
	newChildNode.castShadow = true;
	newChildNode.receiveShadow = true;
	return newChildNode;
}

VWModelLoader.prototype.getObjectMaterial = function(inMaterialId, inObjectColor, repeatU, repeatV){
	var material = null;
	if(inMaterialId != 0){
		var matData = this._matData[inMaterialId];
		var texture = undefined;
		if (matData.hasColorTex)
			texture = this._texData[matData.texName];

		if (texture === undefined) {
			if (this._bIsWhiteModel)
				material = this.nMatNoText(1.0, 1.0, 1.0,matData.opacity);
			else
				material = this.nMatNoText(matData.color.r, matData.color.g, matData.color.b,matData.opacity);
		}
		else {
			if (matData.color.r == 0.0 && matData.color.g == 0.0 && matData.color.b == 0.0 )
				material = this.nMatwText(1.0,1.0,1.0,matData.opacity,texture,matData.colorBytesPerPixel == 4 ? true:false, repeatU, repeatV);
			else
				material = this.nMatwText(matData.color.r,matData.color.g,matData.color.b,matData.opacity,texture,matData.colorBytesPerPixel == 4 ? true:false, repeatU, repeatV);
		}
	}
	else {
		if (this._bIsWhiteModel)
			material = this.nMatNoText(1.0, 1.0, 1.0,inObjectColor[3]);
		else
			material = this.nMatNoText(inObjectColor[0], inObjectColor[1], inObjectColor[2],inObjectColor[3]);
	}

	return material;
};

VWModelLoader.prototype.getAppropriateMatData = function(inMaterialId){
	var matData = undefined;
	for(var key in this._matData) {
		if(this._matData[key].originalMatID == inMaterialId)
		{
			matData = this._matData[key];
		}
	}
	return matData;
}

VWModelLoader.prototype.getObjectMaterial2 = function(inMaterialId, inObjectColor, repeatU, repeatV){
	var material = null;

	if(inMaterialId != 0){
		var matData = this.getAppropriateMatData(inMaterialId);
		if(matData == undefined)
		{
			material = this.nMatNoText(inObjectColor[0], inObjectColor[1], inObjectColor[2],inObjectColor[3]);
			return material;
		}

		var texture = undefined;
		if (matData && matData.hasColorTex)
			texture = this._texData[matData.texName];

		if (texture === undefined) {
			if (this._bIsWhiteModel)
				material = this.nMatNoText(1.0, 1.0, 1.0,matData.opacity);
			else
				material = this.nMatNoText(matData.color.r, matData.color.g, matData.color.b,matData.opacity);
		}
		else {
			if (matData.color.r == 0.0 && matData.color.g == 0.0 && matData.color.b == 0.0 )
				material = this.nMatwText(1.0,1.0,1.0,matData.opacity,texture,matData.colorBytesPerPixel == 4 ? true:false, repeatU, repeatV);
			else
				material = this.nMatwText(matData.color.r,matData.color.g,matData.color.b,matData.opacity,texture,matData.colorBytesPerPixel == 4 ? true:false, repeatU, repeatV);
		}
	}
	else {
		if (this._bIsWhiteModel)
			material = this.nMatNoText(1.0, 1.0, 1.0,inObjectColor[3]);
		else
			material = this.nMatNoText(inObjectColor[0], inObjectColor[1], inObjectColor[2],inObjectColor[3]);
	}

	return material;
};

VWModelLoader.prototype.getChildWithSameMaterial = function(parentNode,finalGeom, geometry, matrix) {
	var meshMat = finalGeom.meshMat;
	var materialName = (meshMat.fMaterialID == 0)?(parentNode.name + "_" + meshMat.fMaterialID + "_" + meshMat.fObjectColor[0] + "_" + meshMat.fObjectColor[1] + "_" + meshMat.fObjectColor[2] + "_" + meshMat.fObjectColor[3])
		:(parentNode.name + "_" + meshMat.fMaterialID + "_" +meshMat.fbRepeatU + "_" +meshMat.fbRepeatV);
	if (meshMat.fMeshType == 2) {

		if (meshMat.fMaterialType == 0){
			materialName = materialName + "_" + this._numNones;
			this._numNones++;
		}
		if (meshMat.fMaterialType == 6){
			materialName = materialName + "_" + this._numPatterns;
			this._numPatterns++;
		}
		else if (meshMat.fMaterialType >= 1 && meshMat.fMaterialType <= 4 ){
			materialName = materialName + "_" + this._numGradients;
			this._numGradients++;
		}
		else if (meshMat.fMaterialType == 7) { // hatches
			materialName = materialName + "_" + this._numHatches;
			this._numHatches++;
		}
	}
	var requiredMesh = parentNode.getObjectByName(materialName);
	if(requiredMesh) {
		return requiredMesh;
	}
	else {
		requiredMesh = new THREE.Mesh();
		requiredMesh.castShadow = true;
		requiredMesh.receiveShadow = true;
		var material;

		switch(meshMat.fMeshType){
			case 1: {
				material = new THREE.LineBasicMaterial({color : new THREE.Color(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]), linewidth : meshMat.fLineWeight});
			}
			break;
			case 2:{
				var tMatrix = new THREE.Matrix4().fromArray(matrix);
				var invMatrix = new THREE.Matrix4().getInverse(tMatrix);
				for(var i = 0; i < finalGeom.geometry.Vertices.length ; i+=3) {
					var modVertex = new THREE.Vector3(finalGeom.geometry.Vertices[i],finalGeom.geometry.Vertices[i+1],finalGeom.geometry.Vertices[i+2]);
					modVertex.applyMatrix4(invMatrix);
					finalGeom.geometry.Vertices[i] = modVertex.x;
					finalGeom.geometry.Vertices[i+1] = modVertex.y;
					finalGeom.geometry.Vertices[i+2] = modVertex.z;
					if (finalGeom.flags == 64) // prevent z-fighting for line components
						finalGeom.geometry.Vertices[i+2] += 1;
				}
				switch (meshMat.fMaterialType) {
					case 0:{
						material = new THREE.MeshBasicMaterial({
							color : new THREE.Color(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]),
							opacity : meshMat.fObjectColor[3],
							transparent: (meshMat.fObjectColor[3] < 1) ? true:false,
							side : THREE.DoubleSide,
							polygonOffset: true,
							polygonOffsetFactor: 1.0,
							polygonOffsetUnits: 4.0
						});
						if (finalGeom.flags == 64)
							material = new THREE.LineBasicMaterial({color : new THREE.Color(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]), linewidth : meshMat.fLineWeight});
					}
					break;
					case 1:
					case 2:
					case 3:
					case 4:
					case 6:	{
						finalGeom.geometry.TextureCoord = this.createUVsForPlanarMesh(finalGeom, meshMat);
						geometry.addAttribute('uv', new THREE.BufferAttribute(finalGeom.geometry.TextureCoord, 2));
						material = this.createPlanarMaterial(meshMat);
					}
					break;
					case 7: {
						material = new THREE.LineBasicMaterial({
							color : new THREE.Color(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]),
							linewidth : meshMat.fLineWeight,
							polygonOffset: true,
							polygonOffsetFactor: 1.0,
							polygonOffsetUnits: 4.0
						});
						geometry.addAttribute('color', new THREE.BufferAttribute(new THREE.Vector3(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]), 3));
					}
					break;
					default : {
						finalGeom.geometry.TextureCoord = this.createUVsForPlanarMesh(finalGeom, meshMat);
						geometry.addAttribute('uv', new THREE.BufferAttribute(finalGeom.geometry.TextureCoord, 2));
						material = this.getObjectMaterial(meshMat.fMaterialID, meshMat.fObjectColor, meshMat.fbRepeatU, meshMat.fbRepeatV);
						if (meshMat.fTextWorldHeight == 0) {
							material = new THREE.MeshBasicMaterial({
								color : material.color,
								opacity : material.opacity,
								transparent: material.transparent,
								side : material.side,
								map: material.map,
								polygonOffset: true,
								polygonOffsetFactor: 1.0,
								polygonOffsetUnits: 4.0
							});
						}
						else{ // prevent z-fighting for text
							material.polygonOffset = true;
							material.polygonOffsetFactor = -1.0;
							material.polygonOffsetUnits = 4.0;
						}
					}
					break;
				}
				for(var i = 0; i < finalGeom.geometry.Vertices.length ; i+=3) {
					var modVertex = new THREE.Vector3(finalGeom.geometry.Vertices[i],finalGeom.geometry.Vertices[i+1],finalGeom.geometry.Vertices[i+2]);
					modVertex.applyMatrix4(tMatrix);
					finalGeom.geometry.Vertices[i] = modVertex.x;
					finalGeom.geometry.Vertices[i+1] = modVertex.y;
					finalGeom.geometry.Vertices[i+2] = modVertex.z;
				}
			}
			break;
			case 5:{
				material = new THREE.PointsMaterial({ vertexColors: THREE.VertexColors });
				material.size = window.devicePixelRatio;
			}
			break;
			default:{
				material = this.getObjectMaterial(meshMat.fMaterialID, meshMat.fObjectColor, meshMat.fbRepeatU, meshMat.fbRepeatV);
			}
			break;
		}
		requiredMesh.name = materialName;
		requiredMesh.material = material;
		parentNode.add(requiredMesh);
		return requiredMesh;
	}
};

// alternative version of getChildWithSameMaterial.
VWModelLoader.prototype.getChildWithSameMaterial2 = function(message, geometry) {
	var material;

	switch(message.fMeshType)
	{
		case 1: {
			material = new THREE.LineBasicMaterial({color : new THREE.Color(message.MaterialInfo.fObjectColor[0], message.MaterialInfo.fObjectColor[1], message.MaterialInfo.fObjectColor[2]), linewidth : message.MaterialInfo.fLineWeight});
		}
		break;
		case 2:{
			var tMatrix = new THREE.Matrix4().fromArray(message.matrix);
			var invMatrix = new THREE.Matrix4().getInverse(tMatrix);
			for(var i = 0; i < message.fVertices.length ; i+=3) {
				var modVertex = new THREE.Vector3(message.fVertices[i],message.fVertices[i+1],message.fVertices[i+2]);
				modVertex.applyMatrix4(invMatrix);
				message.fVertices[i] = modVertex.x;
				message.fVertices[i+1] = modVertex.y;
				message.fVertices[i+2] = modVertex.z;
				if (message.Flags == 64) // prevent z-fighting for line components
					message.fVertices[i+2] += 1;
			}
			var meshMat = message.MaterialInfo;
			switch (meshMat.fMaterialType) {
				case 0:{
					material = new THREE.MeshBasicMaterial({
						color : new THREE.Color(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]),
						opacity : meshMat.fObjectColor[3],
						transparent: (meshMat.fObjectColor[3] < 1) ? true:false,
						side : THREE.DoubleSide,
						polygonOffset: true,
						polygonOffsetFactor: 1.0,
						polygonOffsetUnits: 4.0
					});
					if (message.Flags == 64) {
						material = new THREE.LineBasicMaterial({color : new THREE.Color(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]), linewidth : meshMat.fLineWeight});
					}
					break;
				}
				case 1:
				case 2:
				case 3:
				case 4:
				case 6:	{
					message.fUVs = this.createUVsForPlanarMesh2(message, meshMat);
					geometry.addAttribute('uv', new THREE.BufferAttribute(message.fUVs, 2));
					material = this.createPlanarMaterial(meshMat, message.fMaterialID);
					break;
				}
				case 7: {
					material = new THREE.LineBasicMaterial({
						color : new THREE.Color(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]),
						linewidth : meshMat.fLineWeight,
						polygonOffset: true,
						polygonOffsetFactor: 1.0,
						polygonOffsetUnits: 4.0
					});
					geometry.addAttribute('color', new THREE.BufferAttribute(new THREE.Vector3(meshMat.fObjectColor[0], meshMat.fObjectColor[1], meshMat.fObjectColor[2]), 3));
				break;
				}
				default : {
					message.fUVs = this.createUVsForPlanarMesh2(message, meshMat);
					geometry.addAttribute('uv', new THREE.BufferAttribute(message.fUVs, 2));
					material = this.getObjectMaterial2(message.fMaterialID, meshMat.fObjectColor, meshMat.fbRepeatU, meshMat.fbRepeatV);
					if (meshMat.fTextWorldHeight == 0) {
						material = new THREE.MeshLambertMaterial({
							color : material.color,
							opacity : material.opacity,
							transparent: material.transparent,
							side : material.side,
							map: material.map,
							polygonOffset: true,
							polygonOffsetFactor: 1.0,
							polygonOffsetUnits: 4.0
						});
					}
					else { // prevent z-fighting for text
						material.polygonOffset = true;
						material.polygonOffsetFactor = -1.0;
						material.polygonOffsetUnits = 4.0;
					}
					break;
				}
			}
			for(var i = 0; i < message.fVertices.length ; i+=3) {
				var modVertex = new THREE.Vector3(message.fVertices[i],message.fVertices[i+1],message.fVertices[i+2]);
				modVertex.applyMatrix4(tMatrix);
				message.fVertices[i] = modVertex.x;
				message.fVertices[i+1] = modVertex.y;
				message.fVertices[i+2] = modVertex.z;
			}
		}
		break;
		case 5:{
			material = new THREE.PointsMaterial({ vertexColors: THREE.VertexColors });
			material.size = window.devicePixelRatio;
			//material.sizeAttenuation = false;
		}
		break;
		default:{
			material = this.getObjectMaterial2(message.fMaterialID, message.MaterialInfo.fObjectColor,  message.MaterialInfo.fbRepeatU,  message.MaterialInfo.fbRepeatV);
		}
		break;
	}
	return material;
};

VWModelLoader.prototype.mergeGeometry = function(geometryActual, toBeMergedGeometry){
	if ( toBeMergedGeometry instanceof THREE.BufferGeometry === false || geometryActual instanceof THREE.BufferGeometry === false) {
        console.error( 'THREE.BufferGeometry.merge(): geometry not an instance of THREE.BufferGeometry.', toBeMergedGeometry );
        return;
    }
	var mergedBufferGeometry = new THREE.BufferGeometry();
    var attributes = geometryActual.attributes;
    if( geometryActual.index ){
        var indices = toBeMergedGeometry.index.array;
        var offset = attributes[ 'position' ].count;
        for( var i = 0, il = indices.length; i < il; i++ ) {
            indices[i] = offset + indices[i];
        }
		mergedBufferGeometry.setIndex(new THREE.BufferAttribute(Uint32ArrayConcat( geometryActual.index.array, indices ),1));
    }
    for ( var key in attributes ) {
        if ( toBeMergedGeometry.attributes[ key ] === undefined ) continue;
		mergedBufferGeometry.addAttribute(key,new THREE.BufferAttribute(Float32ArrayConcat( attributes[ key ].array, toBeMergedGeometry.attributes[ key ].array),attributes[ key ].itemSize));
    }
	toBeMergedGeometry.dispose();
	geometryActual.dispose();

    return mergedBufferGeometry;

    /***
     * @param {Float32Array} first
     * @param {Float32Array} second
     * @returns {Float32Array}
     * @constructor
     */
    function Float32ArrayConcat(first, second)
    {
    	var result;
    	// try-catch added here as a patch for crashing models on mobile devices.
    	try {
	        var firstLength = first.length,
	        result = new Float32Array(firstLength + second.length);
	        result.set(first);
	        result.set(second, firstLength);
	    }
	    catch(RangeError) {
	    	$("#startupTutorial").css({display:'none'});
	    	this.dispatchEvent({type:'errorProcessing',message : "Web View cannot continue loading objects."});
	    	throw new Error("Allocation went horribly wrong. Ending web view loading.");
	    }
        return result;
    }

    /**
     * @param {Uint32Array} first
     * @param {Uint32Array} second
     * @returns {Uint32Array}
     * @constructor
     */
    function Uint32ArrayConcat(first, second)
    {
    	var result;
    	try {
	        var firstLength = first.length;
	        result = new Uint32Array(firstLength + second.length);
	        result.set(first);
	        result.set(second, firstLength);
	    }
        catch(RangeError) {
	    	$("#startupTutorial").css({display:'none'});
	    	this.dispatchEvent({type:'errorProcessing',message : "Web View cannot continue loading objects."});
	    	throw new Error("Allocation went horribly wrong. Ending web view loading.");
	    }
	  	return result;
    }

}

VWModelLoader.prototype.createUVsForPlanarMesh = function(inGeometry, inMaterial){
	var texCoords = [];
	if (inGeometry.geometry.TextureCoord === undefined) {
		if (inMaterial.fMaterialType == 7) { // hatches

		}
		else if (inMaterial.fMaterialType == 5 || (inMaterial.fMaterialType >= 1 && inMaterial.fMaterialType <= 4)){ // image fill + gradients
			var origin = new THREE.Vector2(inMaterial.fOrigin[0], inMaterial.fOrigin[1]);
			var iAxisPt = new THREE.Vector2(inMaterial.fIAxisPt[0], inMaterial.fIAxisPt[1]);
			var jAxisPt = new THREE.Vector2(inMaterial.fJAxisPt[0], inMaterial.fJAxisPt[1]);

			iAxisPt.sub(origin);
			jAxisPt.sub(origin);
			var zw = new THREE.Vector2(iAxisPt.length(), jAxisPt.length());
			iAxisPt.normalize();

			for (var i=0; i < inGeometry.geometry.Vertices.length; i+=3) {
				var newUV = new THREE.Vector2(inGeometry.geometry.Vertices[i] - origin.x, inGeometry.geometry.Vertices[i+1] - origin.y);
				var xUV = newUV.clone().dot(iAxisPt);
				var yUV = newUV.clone().dot(new THREE.Vector2(-iAxisPt.y, iAxisPt.x));
				newUV = new THREE.Vector2(xUV,yUV);
				newUV.divide(zw);
				texCoords.push(newUV.x); texCoords.push(newUV.y);
				if( inMaterial.fbIsMirrored )
			      texCoords[i] = 1.0 - texCoords[i];
			    if( inMaterial.fbIsFlipped )
			      texCoords[i+1] = 1.0 - texCoords[i+1];
			}
		}
	}

	return new Float32Array(texCoords);
};

VWModelLoader.prototype.createUVsForPlanarMesh2 = function(message, inMaterial){
	var texCoords = [];
	if (message.fUVs === undefined || message.fUVs.length <= 0) {
		if (inMaterial.fMaterialType == 7) { // hatches

		}
		else if (inMaterial.fMaterialType == 5 || (inMaterial.fMaterialType >= 1 && inMaterial.fMaterialType <= 4)){ // image fill + gradients
			var origin = new THREE.Vector2(inMaterial.fOrigin[0], inMaterial.fOrigin[1]);
			var iAxisPt = new THREE.Vector2(inMaterial.fIAxisPt[0], inMaterial.fIAxisPt[1]);
			var jAxisPt = new THREE.Vector2(inMaterial.fJAxisPt[0], inMaterial.fJAxisPt[1]);

			iAxisPt.sub(origin);
			jAxisPt.sub(origin);
			var zw = new THREE.Vector2(iAxisPt.length(), jAxisPt.length());
			iAxisPt.normalize();

			for (var i=0; i < message.fVertices.length; i+=3) {
				var newUV = new THREE.Vector2(message.fVertices[i] - origin.x, message.fVertices[i+1] - origin.y);
				var xUV = newUV.clone().dot(iAxisPt);
				var yUV = newUV.clone().dot(new THREE.Vector2(-iAxisPt.y, iAxisPt.x));
				newUV = new THREE.Vector2(xUV,yUV);
				newUV.divide(zw);
				texCoords.push(newUV.x); texCoords.push(newUV.y);
				if( inMaterial.fbIsMirrored )
			      texCoords[i] = 1.0 - texCoords[i];
			    if( inMaterial.fbIsFlipped )
			      texCoords[i+1] = 1.0 - texCoords[i+1];
			}
		}
	}

	return new Float32Array(texCoords);
};

VWModelLoader.prototype.createPlanarMaterial = function(inMaterial, inMatId) {

	var shaderMat;
	var objMaterial;
	if (inMatId == undefined)
		objMaterial = this.getObjectMaterial(inMaterial.fMaterialID, inMaterial.fObjectColor);
	else
		objMaterial = this.getObjectMaterial2(inMatId, inMaterial.fObjectColor);
	if (inMaterial.fMaterialType == 6) { // patterns
		var uniforms = {
			u_pattern : {type: "v4", value: new THREE.Vector4(inMaterial.fPattern[0], inMaterial.fPattern[1], inMaterial.fPattern[2], inMaterial.fPattern[3])},
			u_backgroundColor : {type: "v4", value : new THREE.Vector4(inMaterial.fBackgroundColor[0], inMaterial.fBackgroundColor[1], inMaterial.fBackgroundColor[2], inMaterial.fBackgroundColor[3])},
			u_foreColor : {type: "v4", value : new THREE.Vector4(inMaterial.fObjectColor[0], inMaterial.fObjectColor[1], inMaterial.fObjectColor[2], inMaterial.fObjectColor[3])}
		};
		shaderMat = new THREE.ShaderMaterial( {
			uniforms : uniforms,
			vertexShader:document.getElementById('patternVertexShader').textContent,
			fragmentShader:document.getElementById('patternFragmentShader').textContent,
			polygonOffset: true,
			polygonOffsetFactor: 2.0,
			polygonOffsetUnits: 4.0
		});
		shaderMat.color = objMaterial.color;
		shaderMat.opacity = objMaterial.opacity;
		shaderMat.side = objMaterial.side;
	}
	else { // gradients
		var origin = new THREE.Vector2(inMaterial.fOrigin[0], inMaterial.fOrigin[1]);
		var iAxisPt = new THREE.Vector2(inMaterial.fIAxisPt[0], inMaterial.fIAxisPt[1]);
		iAxisPt.sub(origin);
		iAxisPt.normalize();
		var uniforms = {
			u_reverse : {value: inMaterial.fbIsMirrored},
			u_repeat : {value : inMaterial.fbIsRepeated},
			u_foreColor : {value : new THREE.Vector4(inMaterial.fObjectColor[0], inMaterial.fObjectColor[1], inMaterial.fObjectColor[2], inMaterial.fObjectColor[3])},
			u_filltype : {value : inMaterial.fMaterialType},
			u_iaxis : {value : iAxisPt},
			u_ilength : {value : iAxisPt.length()},
			u_Tex : {value : objMaterial.map}
		};
		shaderMat = new THREE.ShaderMaterial( {
			uniforms : uniforms,
			vertexShader:document.getElementById('gradVertexShader').textContent,
			fragmentShader:document.getElementById('gradientFragmentShader').textContent,
			polygonOffset: true,
			polygonOffsetFactor: 2.0,
			polygonOffsetUnits: 4.0
		});
		shaderMat.color = objMaterial.color;
		shaderMat.opacity = objMaterial.opacity;
		shaderMat.side = objMaterial.side;
	}
	return shaderMat;
};

/*
	VWManager
	The VW Manager class is created to manage the loading and modifications in the geometry. 
	Created By : 
*/

"use strict";
self.VWComposerRender = function(manager, renderer) {
	var canvas = document.querySelectorAll('canvas')[1];
	
	this._effectComposer = new THREE.EffectComposer( renderer );
	this._effectComposer.renderTarget1.stencilBuffer = true;
	this._effectComposer.renderTarget2.stencilBuffer = true;
	
	// #For_Andrew Changes for Static Images
	this._backgroundRenderPass = new THREE.RenderPass( manager._backgroundScene, manager._camera );
	this._clearMask = new THREE.ClearMaskPass();	
	var renderTargetParameters = {
			minFilter: THREE.LinearFilter,
			magFilter: THREE.LinearFilter,
			format: THREE.RGBAFormat,
			stencilBuffer: false
	};
	var renderTarget = new THREE.WebGLRenderTarget( canvas.width, canvas.height, renderTargetParameters );
	renderTarget.texture.format = THREE.RGBAFormat;
	this._effectSave = new THREE.SavePass( renderTarget );
	var pars = { minFilter: THREE.LinearFilter, magFilter: THREE.LinearFilter, format: THREE.RGBAFormat  };
	this._depthRenderTarget = new THREE.WebGLRenderTarget( canvas.width, canvas.height, pars );
	
	var pars = { minFilter: THREE.LinearFilter, magFilter: THREE.LinearFilter, format: THREE.RGBAFormat  };
	this._depthRenderTarget2 = new THREE.WebGLRenderTarget( canvas.width, canvas.height, pars );
	
	this._depthMaterial = new THREE.MeshDepthMaterial();
	//this._clippingPlanes = new THREE.WebGLClipping();
	this._clippingPlaneUniforms;
	this._normalMaterial;
	this._normalRenderTarget;
	this._effectFXAA = new THREE.ShaderPass( THREE.FXAAShader );
	this._aoPercantage = 50;
	this._aoSize = 200;
	this._ssaoPass;
	this._edgeShader;
	this._edgeShaderDraw;
	this.initPostprocessing(manager,renderer);
	this._cloneCompleted = false;
	this._imagePropScene = new THREE.Scene();	
}

VWComposerRender.prototype = new THREE.EventDispatcher();

VWComposerRender.prototype.copyPlantObjeccts = function(inMesh)
{
	if(inMesh.vgxPlant )
	{
		var newMesh = inMesh.clone();
		/*newMesh.customDepthMaterial = new THREE.MeshDepthMaterial( {

			depthPacking: THREE.RGBADepthPacking,
			map: inMesh.material.map,
			alphaTest: 0.2

		} );*/
		
		this._imagePropScene.add(newMesh);
	}
	
	var objects = inMesh.children;
	for(var i = 0; i < objects.length; ++i)
	{
		this.copyPlantObjeccts(objects[i]);
	}
}

VWComposerRender.prototype.setVisibilityOfNonShaderObjects = function(inMesh,visiblitySet)
{
	if(inMesh.vgxPlant )
	{
		inMesh.visible = visiblitySet;
	}
	
	var objects = inMesh.children;
	for(var i = 0; i < objects.length; ++i)
	{
		this.setVisibilityOfNonShaderObjects(objects[i], visiblitySet);
	}
}

VWComposerRender.prototype.render = function() {
	var self = this;
	return function(){
		manager.dynamicNearFar(); // This check is necessary for clipping 
		if(self._ssaoPass) {
			
			self._ssaoPass.uniforms[ 'u_NearFar' ].value = new THREE.Vector2( manager._camera.near, manager._camera.far);
		}
		
		if(!self._cloneCompleted)
		{
			self.copyPlantObjeccts(scene);
			self._cloneCompleted = true;
		}
		
		self.setVisibilityOfNonShaderObjects(scene,false);
		
		scene.overrideMaterial = self._normalMaterial;
		renderer.render( scene, camera, self._normalRenderTarget, true );
		
		// First pass for depth texture generation.
		scene.overrideMaterial = self._depthMaterial;
		renderer.render( scene, camera, self._depthRenderTarget, true );
		self.setVisibilityOfNonShaderObjects(scene,true);
		
		
		renderer.render( self._imagePropScene, camera, self._depthRenderTarget2, true );
		
		scene.overrideMaterial = null;
		
		// All the post processing shaders are then executed here. 
		self._effectComposer.render(); 
		if(skyBox && !manager._backgroundScene.staticBackground)
			skyBox.position.copy(camera.position);
	}
}

VWComposerRender.prototype.windowResize = function() {
	var self = this;
	return function(){
		camera.aspect = window.innerWidth / window.innerHeight;
		camera.updateProjectionMatrix();
		renderer.setSize( window.innerWidth, window.innerHeight );
		renderer.setViewport(0,0,window.innerWidth, window.innerHeight);
		renderer.shadowMap.renderReverseSided = true;
		
		var canvas = document.querySelectorAll('canvas')[1];
		
		self._effectFXAA.uniforms[ 'resolution' ].value.set(  1 / canvas.width, 1 / canvas.height);
		self._depthRenderTarget.setSize( canvas.width,  canvas.height );
		self._depthRenderTarget2.setSize( canvas.width,  canvas.height );

		if(self._ssaoPass)
			self._ssaoPass.uniforms[ 'u_ScreenRes' ].value = new THREE.Vector2( window.innerWidth*window.devicePixelRatio, window.innerHeight*window.devicePixelRatio );
		
		if(self._edgeShader && self._edgeShaderDraw) {
			self._edgeShader.uniforms[ "u_TexSize" ].value = new THREE.Vector2(1.0/window.innerWidth, 1.0/window.innerHeight);
			self._edgeShaderDraw.uniforms[ "u_TexSize" ].value = new THREE.Vector2(1.0/canvas.width, 1.0/ canvas.height);
			self._edgeShader.uniforms[ "u_Viewport" ].value = new THREE.Vector4(0,0,window.innerWidth, window.innerHeight);
		}
		
		self._effectComposer.setSize( canvas.width, canvas.height );
		renderer.setViewport(0,0,window.innerWidth, window.innerHeight);
		
	}
}

VWComposerRender.prototype.updateEdgeShaderCode = function(data) {
	if(!this._edgeShader || !this._edgeShaderDraw)
		return;
	if(data.thickness)
		this._edgeShaderDraw.uniforms[ "u_EdgeWidth" ].value = data.thickness;
	if(data.creaseAngle)
		this._edgeShader.uniforms[ "u_CreaseThresh" ].value = new THREE.Vector2(Math.cos(data.creaseAngle*Math.PI/180), Math.cos((data.creaseAngle/2.0)*Math.PI/180));
	
}

VWComposerRender.prototype.updateSSAOShaderCode = function(data) {
	if(!this._ssaoPass)
		return;
	var aoPowerWeight = .5;
	var aoSizeWeight = .5;
	var AOSizeDefault = 254.0; 
	if(data.size) {
		this._aoSize = data.size;
		this._ssaoPass.uniforms[ 'u_AOInput' ].value = new THREE.Vector2(this._aoSize * aoSizeWeight, (this._aoPercantage * aoPowerWeight * (this._aoSize/ AOSizeDefault)) );
	}
	if(data.strength){
		this._aoPercantage = data.strength;
		this._ssaoPass.uniforms[ 'u_AOInput' ].value = new THREE.Vector2(this._aoSize * aoSizeWeight, (this._aoPercantage * aoPowerWeight * (this._aoSize/ AOSizeDefault)) );
	}
}

VWComposerRender.prototype.initEdgeShader = function() {
	if(this._edgeShader && this._edgeShaderDraw)
		return;
	var canvas = document.querySelectorAll('canvas')[1];
	this._edgeShader = new THREE.ShaderPass( THREE.EdgeShaderDetect );
	this._edgeShaderDraw = new THREE.ShaderPass( THREE.EdgeShaderDraw );
	var creaseAngle;
	var depthAngle;
	var fCreaseAngle = 50;
	creaseAngle = fCreaseAngle;
	depthAngle = creaseAngle / 2.0;
	this._edgeShader.uniforms[ "u_VertexIDs" ].value = this._normalRenderTarget.texture;
	this._edgeShader.uniforms[ "u_DepthTex" ].value = (/Mobi/ && /Mobi/.test(navigator.userAgent || navigator.vendor || window.opera))?this._depthRenderTarget.texture:this._depthRenderTarget.depthTexture;
	//this._edgeShader.uniforms[ "u_DepthTex" ].value = this._depthRenderTarget.depthTexture;
	this._edgeShader.uniforms[ "u_TexSize" ].value = new THREE.Vector2(1.0/window.innerWidth, 1.0/window.innerHeight);
	this._edgeShader.uniforms[ "u_Viewport" ].value = new THREE.Vector4(0,0,window.innerWidth, window.innerHeight);
	this._edgeShader.uniforms[ "u_CreaseThresh" ].value = new THREE.Vector2(Math.cos(creaseAngle*Math.PI/180), Math.cos(depthAngle*Math.PI/180));
	this._edgeShader.uniforms[ "u_RenderPassDepth" ].value = this._depthRenderTarget2.texture;
	
	this._edgeShaderDraw.uniforms[ "u_TexSize" ].value = new THREE.Vector2(1.0/canvas.width, 1.0/canvas.height);
	this._edgeShaderDraw.uniforms[ "u_SrcColor" ].value = this._effectSave.renderTarget.texture;
	this._edgeShaderDraw.uniforms[ "u_EdgeWidth" ].value = 2;
	this._edgeShaderDraw.uniforms[ "u_LineColor" ].value = 1.0;
	
	if(this._ssaoPass) {
		this._effectComposer.insertPass( this._edgeShader, 5 );
		this._effectComposer.insertPass( this._edgeShaderDraw, 6 );
	}
	else {
		this._effectComposer.insertPass( this._edgeShader, 4 );
		this._effectComposer.insertPass( this._edgeShaderDraw, 5 );
	}
}

VWComposerRender.prototype.initAmbientOcclusionShader = function(camera) {
	if(/Mobi/.test(navigator.userAgent || navigator.vendor || window.opera))
		return;
	if(this._ssaoPass )
		return;
	var aoPowerWeight = .5;
	var aoSizeWeight = .5;
	var AOSizeDefault = 254.0; 
	this._aoPercantage = 50;
	this._aoSize = 200;
	this._ssaoPass = new THREE.ShaderPass( THREE.SSAOShader );
	this._ssaoPass.uniforms[ 'u_IsAOOrFilter' ].value = 0;
	this._ssaoPass.uniforms[ 'u_ScreenRes' ].value = new THREE.Vector2( this._depthRenderTarget.width, this._depthRenderTarget.height );
	this._ssaoPass.uniforms[ 'u_InvProj' ].value = new THREE.Matrix4().getInverse(camera.projectionMatrix);
	this._ssaoPass.uniforms[ 'u_UVBound' ].value = new THREE.Vector4(0,0,this._depthRenderTarget.width/this._depthRenderTarget.height,1);//
	this._ssaoPass.uniforms[ 'u_NearFar' ].value = new THREE.Vector2( camera.near, camera.far);
	this._ssaoPass.uniforms[ 'u_TanHalfFOV' ].value = Math.tan((camera.fov/2) * (Math.PI/180));
	this._ssaoPass.uniforms[ 'u_DepthTex' ].value = (/Mobi/ && /Mobi/.test(navigator.userAgent || navigator.vendor || window.opera))?this._depthRenderTarget.texture:this._depthRenderTarget.depthTexture;
	//this._ssaoPass.uniforms[ 'u_DepthTex' ].value = this._depthRenderTarget.depthTexture;
	this._ssaoPass.uniforms[ 'u_AOInput' ].value = new THREE.Vector2(this._aoSize * aoSizeWeight, (this._aoPercantage * aoPowerWeight * (this._aoSize/ AOSizeDefault)) );
	this._ssaoPass.uniforms[ 'u_AOTex' ].value = null;//
	this._ssaoPass.uniforms[ 'u_VertexIDs' ].value = this._normalRenderTarget.texture;
	
	this._effectComposer.insertPass( this._ssaoPass,3 );
	//this._effectComposer.insertPass( this._effectSave, 4 );
}

VWComposerRender.prototype.initPostprocessing = function(manager, renderer) {
	renderer.setSize( window.innerWidth, window.innerHeight );
	var canvas = document.querySelectorAll('canvas')[1];
	var gl;
	try {
		gl = canvas.getContext('webgl2');
	} catch (err) {
		console.error(err);
	}
	var isWebGL2 = ( typeof THREE.WebGL2RenderingContext !== 'undefined' && gl instanceof THREE.WebGL2RenderingContext );
	
	this._depthRenderTarget.texture.format = THREE.RGBAFormat;
	this._depthRenderTarget.texture.generateMipmaps = false;
	this._depthRenderTarget.stencilBuffer = false;
	this._depthRenderTarget.depthBuffer = true;
	// The depth texture here when used in the edge detection creates artifact lines on the scene. We believe this is because of the resolution of the depth texture being used. Now when we do not initialize this depth texture. The output is written to the texture (render buffer) data which has more resolution on mobile devices. The problem here is, The threshold used in the depth based edges has become too large making only those edges visible which are in vicinity to the background skybox image. 
	// We are trying to find a solution for this, our approach will be to adjust the threshold accroding to the depth calculated or by looking for a better way to a good smooth depth variations. 
	if(/Mobi/ && !/Mobi/.test(navigator.userAgent || navigator.vendor || window.opera)){
		this._depthRenderTarget.depthTexture = new THREE.DepthTexture();
		this._depthRenderTarget.depthTexture.type = isWebGL2 ? THREE.FloatType : THREE.UnsignedShortType;
	}
	
	this._depthRenderTarget2.texture.format = THREE.RGBAFormat;
	this._depthRenderTarget2.texture.generateMipmaps = false;
	// The depth texture here when used in the edge detection creates artifact lines on the scene. We believe this is because of the resolution of the depth texture being used. Now when we do not initialize this depth texture. The output is written to the texture (render buffer) data which has more resolution on mobile devices. The problem here is, The threshold used in the depth based edges has become too large making only those edges visible which are in vicinity to the background skybox image. 
	// We are trying to find a solution for this, our approach will be to adjust the threshold accroding to the depth calculated or by looking for a better way to a good smooth depth variations. 
	
	
	// THREE.js allows us to overwrite the material of all the meshes at once by providing override material. This helped us to write a shader material code that allowed us to create the normal map
	// Depth texture map process. 
	this._depthMaterial = new THREE.MeshDepthMaterial();
	this._depthMaterial.depthPacking = THREE.RGBADepthPacking;
	this._depthMaterial.blending = THREE.NoBlending;
	this._depthMaterial.side = THREE.DoubleSide;
	
	this._normalMaterial = new THREE.ShaderMaterial( {
		//uniforms:this._clippingPlaneUniforms,
		clipping: true,
		clippingPlanes : (manager)?manager._ccPlanes:[],
		vertexShader: document.getElementById( 'postProcessVertexShader' ).textContent,
		fragmentShader: document.getElementById( 'postProcessFragmentShader' ).textContent
	} );
	
	this._normalMaterial.side = THREE.DoubleSide;
	this._normalMaterial.depthPacking = THREE.RGBADepthPacking;
	this._normalMaterial.blending = THREE.NoBlending;

	var pars1 = { minFilter: THREE.LinearFilter, magFilter: THREE.LinearFilter, format: THREE.RGBAFormat };
	// RenderTarget for normal map.
	this._normalRenderTarget  = new THREE.WebGLRenderTarget(canvas.width, canvas.height, pars1 );
	this._normalRenderTarget.texture.generateMipmaps = false;
	
	//
	this._effectSave.enabled = true;
	this._effectFXAA.uniforms[ 'resolution' ].value.set( 1 / canvas.width, 1 / canvas.height );
	
	// Background scene. 
	var clearMask = new THREE.ClearMaskPass();	
	var effectCopy = new THREE.ShaderPass(THREE.CopyShader);
	var renderModelMask = new THREE.MaskPass(manager._scene, manager._camera);
	effectCopy.renderToScreen = true;
	// Remove this if not producing good effect.
	renderer.autoClear = false;
	// Initialization of the post processing shader in THREE.js
	var renderPass = new THREE.RenderPass( manager._scene, manager._camera );
	renderPass.clear = false;
	
	this._effectComposer.renderTarget1.stencilBuffer = true;
	this._effectComposer.renderTarget2.stencilBuffer = true;
	this._effectComposer.addPass(  this._backgroundRenderPass,true );
	this._effectComposer.addPass( renderPass );
	this._effectComposer.addPass( renderModelMask);
	this._effectComposer.addPass( this._effectSave );
	this._effectComposer.addPass( clearMask);
	this._effectComposer.addPass( this._effectFXAA );
	this._effectComposer.addPass( effectCopy );
	this._effectComposer.setSize( canvas.width, canvas.height );
	renderer.setViewport(0,0,window.innerWidth, window.innerHeight);
}

/***********************************************************
// Bilateral filtering of the Ambient occlusion
	ssaoPassBilateral = new THREE.ShaderPass( THREE.SSAOShaderBilateral );
	ssaoPassBilateral.uniforms[ 'u_ScreenRes' ].value = new THREE.Vector2( depthRenderTarget.width, depthRenderTarget.height );
	ssaoPassBilateral.uniforms[ 'u_InvProj' ].value = new THREE.Matrix4().getInverse(camera.projectionMatrix);
	ssaoPassBilateral.uniforms[ 'u_UVBound' ].value = new THREE.Vector4(0,0,depthRenderTarget.width/depthRenderTarget.height,1);//
	ssaoPassBilateral.uniforms[ 'u_NearFar' ].value = new THREE.Vector2( camera.near, camera.far);
	ssaoPassBilateral.uniforms[ 'u_TanHalfFOV' ].value = Math.tan((camera.fov/2) * (Math.PI/180));
	ssaoPassBilateral.uniforms[ 'u_DepthTex' ].value = depthRenderTarget.depthTexture;
	ssaoPassBilateral.uniforms[ 'u_AOInput' ].value = new THREE.Vector2(aoSize * aoSizeWeight, (aoPercantage * aoPowerWeight * (aoSize/ AOSizeDefault)) );
	ssaoPassBilateral.uniforms[ 'u_VertexIDs' ].value = null;//
************************************************************/
/*
	VWManager
	The VW Manager class is created to manage the loading and modifications in the geometry. 
	Created By : 
*/

"use strict";
self.VWNormalRenderer = function(manager, renderer) {
	this._effectComposer = new THREE.EffectComposer( renderer );
	this._effectFXAA = new THREE.ShaderPass( THREE.FXAAShader );
	this._bIsChromeiOS = mobileAndTabletcheck() && navigator.userAgent.match('CriOS');
	this._backgroundRenderPass = new THREE.RenderPass( manager._backgroundScene, manager._camera );
	this._bDoesAOPass = false;
}

VWNormalRenderer.prototype = new THREE.EventDispatcher();

VWNormalRenderer.prototype.render = function() {
	var self = this;
	return function() {
		//if(self._bDoesAOPass)
		manager.dynamicNearFar();
		self._effectComposer.render(); 
		if(skyBox && !manager._backgroundScene.staticBackground)
			skyBox.position.copy(camera.position);
	}
}

VWNormalRenderer.prototype.windowResize = function() {
	var self = this;
	return function(){
		
		camera.aspect = window.innerWidth / window.innerHeight;
		camera.updateProjectionMatrix();
		renderer.setSize( window.innerWidth, window.innerHeight );
		renderer.setViewport(0,0,window.innerWidth, window.innerHeight);
		renderer.shadowMap.renderReverseSided = true;
		
		
		var canvas = document.querySelectorAll('canvas')[1];
		
		self._effectFXAA.uniforms[ 'resolution' ].value.set(  1 / canvas.width, 1 / canvas.height);

		self._effectComposer.setSize( canvas.width, canvas.height );
		renderer.setViewport(0,0,window.innerWidth, window.innerHeight);
		
	}
}

VWNormalRenderer.prototype.init = function(manager,renderer) {
	var canvas = document.querySelectorAll('canvas')[1];
	this._effectFXAA.uniforms[ 'resolution' ].value.set(  1 / canvas.width, 1 / canvas.height );
	
	// Background scene. 
	var effectCopy = new THREE.ShaderPass(THREE.CopyShader);
	effectCopy.renderToScreen = true;
	
	var renderPass = new THREE.RenderPass( manager._scene, manager._camera );
	renderPass.clear = false;
	
	this._effectComposer.addPass( this._backgroundRenderPass,true );
	this._effectComposer.addPass( renderPass );
	this._effectComposer.addPass( this._effectFXAA );
	this._effectComposer.addPass( effectCopy );
	this._effectComposer.setSize( canvas.width, canvas.height );
	renderer.setViewport(0,0,window.innerWidth, window.innerHeight);
}


/*
	VWManager
	The VW Manager class is created to manage the loading and modifications in the geometry.
	Created By :
*/

"use strict";
self.VWRenderAdaptor = function(manager, renderer) {
	this._composerRenderer = new VWComposerRender(manager, renderer);
	this._normalRenderer = new VWNormalRenderer(manager,renderer);
	this._normalRenderer.init(manager,renderer);
	this._rendererElement = document;
	this._cameraMoving = false;
	this._currentRenderer = 1; // 1 normal renderer, 2 composer renderer
	//if(renderer)
	//	this._rendererElement = renderer;
	var self = this;
	var touchStart = false;
	var timer;

	function onTimeOut(event) {
		if(manager._modelLoadComplete && self._cameraMoving == false){
			renderer.sortObjects = true;
			self.render = self.setRender(self._composerRenderer);
			self.windowResize = self.setWindowResize(self._composerRenderer);
			self._currentRenderer = 2;
			if(controltype != 3)
			{
				renderer.animate(null);
				self.render();
			}
			else
			{
				renderer.animate(animate);
			}
				
			
		}
	}

	function onMouseStart(){
		controlsLOC.update(camera.getWorldDirection());
	}

	function onTouchChange() {
		controlsLOC.DrawOnRotate(camera.getWorldDirection());
	}

	function onCameraChange(event) {
		if(event.buttons == 0)
			return;
		else if(event.which == 0)
			return;
		if(timer)
			clearTimeout(timer);
		renderer.animate(animate);
		timer = setTimeout(onTimeOut,1000);
		self.render = self.setRender(self._normalRenderer);
		self.windowResize = self.setWindowResize(self._normalRenderer);
		this._currentRenderer = 1;

		// NOTE: This is here to hook in modifying the arrow within the Light Direction dialog. Should be eventually moved to LightOrientationControls.
		controlsLOC.DrawOnRotate(camera.getWorldDirection());
	}

	function onTouchStart(event) {
		renderer.sortObjects = false;
		if(timer)
			clearTimeout(timer);
		renderer.animate(animate);
		self.render = self.setRender(self._normalRenderer);
		self.windowResize = self.setWindowResize(self._normalRenderer);
		self._currentRenderer = 1;
		controlsLOC.update(camera.getWorldDirection());
	}


	function onTouchEnd(event) {
		renderer.animate(animate);
		timer = setTimeout(onTimeOut,1000);
	}

	function onCameraWheel(event) {

		if(timer)
			clearTimeout(timer);
		renderer.sortObjects = false;
		renderer.animate(animate);
		timer = setTimeout(onTimeOut,1000);
		self.render = self.setRender(self._normalRenderer);
		self.windowResize = self.setWindowResize(self._normalRenderer);
		this._currentRenderer = 1;
	}

	function onKeyPress(event) {
		switch ( event.keyCode ) {

			case 38: /*up*/
			case 87: /*W*/
			case 37: /*left*/
			case 65: /*A*/
			case 40: /*down*/
			case 83: /*S*/
			case 39: /*right*/
			case 68: /*D*/
			case 82: /*R*/
			case 70: /*F*/
			if(timer)
				clearTimeout(timer);
				renderer.animate(animate);
				timer = setTimeout(onTimeOut,1000);
				self.render = self.setRender(self._normalRenderer);
				self.windowResize = self.setWindowResize(self._normalRenderer);
				this._currentRenderer = 1;
			break;
			default:
			return;
		}

	}

	this.render = this.setRender(this._normalRenderer);
	this.windowResize = this.setWindowResize(this._normalRenderer);

	this._rendererElement.addEventListener( 'mousedown', onMouseStart, false);
	this._rendererElement.addEventListener( 'mousemove', onCameraChange, false );
	this._rendererElement.addEventListener( 'touchmove', onTouchChange, false );
	this._rendererElement.addEventListener( 'touchstart', onTouchStart, false );
	this._rendererElement.addEventListener( 'touchend', onTouchEnd, false );

	this._rendererElement.addEventListener( 'mousewheel', onCameraWheel, false );
	this._rendererElement.addEventListener( 'MozMousePixelScroll', onCameraWheel, false ); // firefox
	window.addEventListener( 'keydown', onKeyPress, false );

}

VWRenderAdaptor.prototype = new THREE.EventDispatcher();

VWRenderAdaptor.prototype.setRender = function(renderStack) {
	return renderStack.render();
}

VWRenderAdaptor.prototype.setWindowResize = function(renderStack) {
	return renderStack.windowResize(camera, renderer);
}

/*
	VWManager
	The VW Manager class is created to manage the loading and modifications in the geometry.
	Created By : Sriram
*/

VWManager = function(scene, backgroundScene, camera, config) {
	this._scene = scene;
	this._backgroundScene = backgroundScene;	this._camera = camera;
	this._mergeGeometries = config?(config.mergeGeometries?config.mergeGeometries:false):false;

	this._clipSimulation;

	this._octreeList = [];
	this._octreeList.push(new THREE.Octree({undeferred: false,depthMax: Infinity,objectsThreshold: 8,overlapPct: 0.15}));
	this._modelInfo = {
		numberOfObjects : 0,
		numberOfTriangles : 0,
		numberOfTextures : 0,
		navigationMeshCreated : false,
	};
	this._boundMin;
	this._boundMax;
	this._boundCenter = new THREE.Vector3();
	this._buildStarted = false;
	this._meshForNavigation = [];
	this._boxGeometry = new THREE.Geometry();
	this._organizedScene = {};
	this._modelLoadComplete = false;
	this._ccPlanes = [];
	this._edgeInfo = {
		edgesOn : false,
		thickness : 1,
		creaseAngle : 70
	};
	this._ambientInfo = {
		ambientOn : false,
		strength : 50,
		size : 24
	};
	this._originalCamFOV = this._camera.fov;
	this._originalCamNear = this._camera.near;
	this._originalCamFar = this._camera.far;

	this._vgx = new VGX(0.2);
	var _loader = new VWModelLoader(this);
	_loader.init(2, Configuration.workerScriptUrl);
	_loader.addEventListener('errorProcessing',this.onErrorMessage.bind(this));
	_loader.addEventListener('objectAdded',this.onSuccessfulLoading.bind(this));
	_loader.addEventListener('modelLoadiongComplete',this.onModelLoadComplete.bind(this));

	this._shadowLight;
	this._defaultLight;
	
	this._renderAdaptor = new VWRenderAdaptor(this, renderer);
	this.sendToLoader = function(data) {
		_loader.loadModel(data);
	};
};

VWManager.prototype = new THREE.EventDispatcher();


VWManager.prototype.dynamicNearFar = function() {

	if(!this._boundMax || !this._boundMin)
		return;
	if(controltype == 3)
		return;
	var BBCenterDistance = this._camera.position.distanceTo(this._boundCenter);
	var BBmaxDistance = this._boundMax.distanceTo(this._boundMin);

	if(BBCenterDistance <= BBmaxDistance/2){
		if(BBCenterDistance < 300)	{			// This is again a hack for the closer objects. But need to evalute why reducing the near directly to 1 starts rendering artifacts when object is near, When object is far from camera the artifacts are not visible now. The out put is not correct when camera goes very much close to the bounding box center.
			this._camera.near = 10;
		}
		else
		this._camera.near = 300;
		this._camera.far = BBmaxDistance * 2 +  BBmaxDistance / 2;
	}
	else {
		this._camera.near = Math.abs(BBCenterDistance - BBmaxDistance/2);
		this._camera.far = Math.abs(BBCenterDistance + BBmaxDistance);
	}
	if(this._camera.far > 2000000)
		this._camera.far = 2000000;
	this._camera.updateProjectionMatrix();
	this._originalCamNear = this._camera.near;
	this._originalCamFar = this._camera.far;
}

VWManager.prototype.loadModel = function() {

	// The following progress bar callback should be coming from VWApp. Since this deals with the UI. But for now we will add this here.
	var progressCallback = function(event) {
		var widthStr = '100%';
		if (event.loaded < event.total)
			widthStr = event.loaded/event.total +'%';

	  setTimeout(function() {
        $("#myBar").css({width:widthStr});
		}, 10);
	};

	var vgxFileName;
	var readStandardVGX = false;
	var search = window.location.search;
	if (search) { // for VCS, dropbox, and others
        var queryString = search.substring(1);
        var pairs = queryString.split('&');
        for (var i = 0; i < pairs.length; ++i) {
            var pair = pairs[i].split('=');
            var name = pair[0];
            var value = pair[1];
            if (name === 'download_url' || value.includes('.vgx')) {
                vgxFileName = decodeURIComponent(value);
            } else if (name === 'readStandard') {
                readStandardVGX = value === '1';
            }
        }
    }

    if (!vgxFileName) {
        if (resources["#filename"] !== undefined) { // local and temporary
            vgxFileName = resources["#filename"];
        } else {
            vgxFileName = "./testFile.vgx";
        }
    }

	this.sendToLoader({
		type: "addModel",
		file : vgxFileName,
		progressBarCallBack : progressCallback,
		readStandardVGX : readStandardVGX
	});
}


VWManager.prototype.onErrorMessage = function(event) {
	message = event.data?event.data:event.message;
	message = JSON.stringify(message);
	console.log(message);
}

VWManager.prototype.createNavigationMap = function(geometry,visible,transparent,name){
	geometry.computeBoundingBox();
	var box = geometry.boundingBox;
	var max = box.max.clone();
	var min = box.min.clone();
	max.applyAxisAngle ( new THREE.Vector3(1.0,0.0,0.0), - Math.PI/2 );
	max.applyAxisAngle ( new THREE.Vector3(0.0,1.0,0.0), Math.PI/2 );
	min.applyAxisAngle ( new THREE.Vector3(1.0,0.0,0.0), - Math.PI/2 );
	min.applyAxisAngle ( new THREE.Vector3(0.0,1.0,0.0), Math.PI/2 );
	if((Math.abs(max.x - min.x) < 2000) && (Math.abs(max.z - min.z) < 2000)) {

		var boxGeometry = new THREE.BoxGeometry(max.x - min.x,max.y - min.y,max.z - min.z);
		boxGeometry.translate(min.x + (max.x - min.x)/2,min.y + (max.y - min.y)/2, min.z + (max.z - min.z)/2);
		var mesh = new THREE.Mesh(boxGeometry);
		mesh.material.side = THREE.DoubleSide;
		mesh.material.transparent = transparent;
		mesh.name = name;

		this._octreeList[0].add(mesh);
		this._octreeList[0].update();
		return -1;
	}
	else {
		geometry.rotateX(- Math.PI/2);
		geometry.rotateY(Math.PI/2);
		var mesh = new THREE.Mesh(geometry);
		mesh.material.side = THREE.DoubleSide;
		mesh.material.transparent = transparent;
		mesh.name = name;
		var octree = new THREE.Octree({undeferred: false,depthMax: Infinity,objectsThreshold: 8,overlapPct: 0.15});
		octree.name = name;
		octree.add(mesh);
		octree.update();
		this._octreeList.push(octree);
		return 0;
	}
}


VWManager.prototype.onSuccessfulLoading = function(event) {
	//console.log(event.data.message);
}

VWManager.prototype.onModelLoadComplete = function(event) {
	this._modelLoadComplete = true;
	this._renderAdaptor.render = this._renderAdaptor.setRender(this._renderAdaptor._composerRenderer);
	this._renderAdaptor._composerRenderer._effectComposer.renderer.shadowMap.enabled = true;
	this._renderAdaptor._normalRenderer._effectComposer.renderer.shadowMap.enabled = true;

	this._clipSimulation = new CAPS.Simulation(this._backgroundScene, this._camera, this._renderAdaptor, this._boundMax, this._boundMin);

	var triangleLimit = 1500000;
	if(mobileAndTabletcheck())
		triangleLimit = 700000;
	if(this._modelInfo.numberOfTriangles > triangleLimit) {
		ShowPopup(resources["#nav_mes_1"])
		octCanBeBuild = false;
		$("#startupTutorial").css({display:'none'});
		return;
	}

	octCanBeBuild = true;
	this.buildNavigationMap(100);
    // show the tutorial to the user
    DoTutorial();
	return;
}

VWManager.prototype.addToNavMesh = function(mesh) {
	this._meshForNavigation.push(mesh);
	if(this._modelLoadComplete ){
		//this._buildStarted = false;
		this.buildNavigationMap(100);
	}
}

VWManager.prototype.buildNavigationMap = function(timer){
	if(!this._modelLoadComplete) {
		octCanBeBuild = false;
		return;
	}
	if(this._buildStarted){
		return;
	}

	this._buildStarted = true;
	var self = this;
	function getNextGeometryForNavMap() {
		for(var i = 0 ; i < self._meshForNavigation.length ; ++i) {
			if(!self._meshForNavigation[i].navMeshCreated) {
				self._meshForNavigation[i].navMeshCreated = true;
				return self._meshForNavigation[i];
			}
		}
		//alert("Nav Mesh Created. You can now start using the first person mode or immersive mode...");
		self._modelInfo.navigationMeshCreated = true;
		return undefined;
	}
	// timer will set for creating the octree.
	// Check the model info where the number of octree objects is to be created.
	// If the number is zero then only use the octree for navigation.
	// Prior to checking the model info check if octree is to be created or not.

	var processGeometry = (function(){
		return function(){
			var node = getNextGeometryForNavMap();
			if(!node) {
				self._buildStarted = false;
				return;
			}
			if(node.geometry && node.geometry instanceof THREE.BufferGeometry){
				if(node.geometry.attributes.position && node.geometry.attributes.position.count > 0){
					setTimeout(function(){
						if (node.geometry.index != null){
							var geometryActualConverted;
							try{
								geometryActualConverted = new THREE.Geometry().fromBufferGeometry(node.geometry);
							}
							catch (error){
								node.geometry.index.array = new Array(node.geometry.attributes.position.count);
								node.geometry.index.count = node.geometry.attributes.position.count;
								node.geometry.groups[0].count = node.geometry.attributes.position.count; // HACK!!! BE VERY CAREFUL HERE SINCE A GEOMETRY CAN HAVE MULTIPLE GROUPS.
								for (var i = 0; i < node.geometry.index.array.length; i++)
									node.geometry.index.array[i] = i;
								geometryActualConverted = new THREE.Geometry().fromBufferGeometry(node.geometry);
							}
							geometryActualConverted.mergeVertices();
							node.geometry = new THREE.BufferGeometry().fromGeometry(geometryActualConverted);
							node.receiveShadow = true;
							node.castShadow = true;
							node.material.needsUpdate = true;
							self.createNavigationMap(geometryActualConverted,node.visible,node.material.transparent, node.name, node.material.opacity);
							processGeometry();
						}
					},timer?timer:300);
				}
			}
		}
	})();
	processGeometry();
}

VWManager.prototype.addCuttingPlane = function(inCutPlane){
	
	if(isNaN(inCutPlane.position[0]) || isNaN(inCutPlane.position[1]) || isNaN(inCutPlane.position[2]) || isNaN(inCutPlane.direction[0]) || isNaN(inCutPlane.direction[1]) || isNaN(inCutPlane.direction[2]))
		return;
	var position = new THREE.Vector3(inCutPlane.position[0],inCutPlane.position[1],inCutPlane.position[2]);
	
	if(!this._boundMax)
		this._boundMax = new THREE.Vector3().copy(position);
	if(!this._boundMin)
		this._boundMin = new THREE.Vector3().copy(position);
	 
	 this._boundMax.x = (this._boundMax.x < position.x)?position.x:this._boundMax.x;
	 this._boundMax.y = (this._boundMax.y < position.y)?position.y:this._boundMax.y;
	 this._boundMax.z = (this._boundMax.z < position.z)?position.z:this._boundMax.z;
	 this._boundMin.x = (this._boundMin.x > position.x)?position.x:this._boundMin.x;
	 this._boundMin.y = (this._boundMin.y > position.y)?position.y:this._boundMin.y;
	 this._boundMin.z = (this._boundMin.z > position.z)?position.z:this._boundMin.z;

}

VWManager.prototype.addAmbientOcclusionData = function(iAOData) {
	this._ambientInfo.ambientOn = true;
	this._renderAdaptor._composerRenderer.initAmbientOcclusionShader(this._camera);
	this._renderAdaptor._normalRenderer._bDoesAOPass = true;
	if(iAOData.size){
		this._ambientInfo.size = iAOData.size;
	}
	if(iAOData.strength) {
		this._ambientInfo.strength = iAOData.strength;
	}
	this._renderAdaptor._composerRenderer.updateSSAOShaderCode(this._ambientInfo);
}

VWManager.prototype.addEdgeShaderData = function(iESData) {
	this._edgeInfo.edgesOn = true;
	this._renderAdaptor._composerRenderer.initEdgeShader();
	if(iESData.thickness){
		this._edgeInfo.thickness = iESData.thickness;
	}
	if(iESData.creaseAngle) {
		this._edgeInfo.creaseAngle = iESData.creaseAngle;
	}
	this._renderAdaptor._composerRenderer.updateEdgeShaderCode(this._edgeInfo);
}

VWManager.prototype.setUserLogo = function(logoData) {
	if(logoData){
		document.getElementById("logo").src = logoData;
	}
}

VWManager.prototype.updateCamera = function(cameraData) {
$("#myProgress").css({display:'none'});
	var position = new THREE.Vector3();
	var lookAt = new THREE.Vector3();
	(cameraData.position)?position = new THREE.Vector3(parseFloat(cameraData.position[0].toFixed(2)), parseFloat(cameraData.position[1].toFixed(2)), parseFloat(cameraData.position[2].toFixed(2))):position = new THREE.Vector3(1000,1000,1000);
	position = rotateVectorForYUp(position);
	(cameraData.lookAt)?lookAt = new THREE.Vector3(parseFloat(cameraData.lookAt[0].toFixed(2)), parseFloat(cameraData.lookAt[1].toFixed(2)), parseFloat(cameraData.lookAt[2].toFixed(2))):lookAt = new THREE.Vector3(0,0,0);
	lookAt = rotateVectorForYUp(lookAt);
	var width = window.innerWidth/2;
	var fov = (cameraData.fov)?cameraData.fov: (2*Math.atan(width/(lookAt.sub(position).length())) * 180 / Math.PI);
	this._camera.fov = parseFloat(fov.toFixed(2));
	this._camera.aspect = window.innerWidth / window.innerHeight;

	this._camera.position.copy(position);
	this._camera.up.x = 0.0;
	this._camera.up.y = 1.0;
	this._camera.up.z = 0.0;

	// store the original camera FOV to obtain later on (i.e. from Stereo mode).
	this._originalCamFOV = this._camera.fov;

	this._camera.updateProjectionMatrix();

	// updating the reset option of orbit  control.
	controlsORC.target0.copy(lookAt);
	controlsORC.target.copy(controlsORC.target0);
	controlsORC.position0.copy(position);

}

VWManager.prototype.SwitchDefaultLight = function(inbIsLightOn){
	if (this._shadowLight !== undefined){
		
		this._shadowLight.castShadow = inbIsLightOn;
		this._defaultLight.visible = !inbIsLightOn;
	}
}

// add default lights for displaying shadows. values taken directly from VGM in default lighting case.
VWManager.prototype.AddDefaultLight = function() {
	if (this._shadowLight === undefined){
		var boundingDiogonal = this._boundMin.distanceTo(this._boundMax);
		this._shadowLight = new THREE.DirectionalLight(0x404040);
	    var pos1 = rotateVectorForYUp(new THREE.Vector3(0,0,0.57735)).multiplyScalar(boundingDiogonal);
	    this._shadowLight.position.set(pos1.x, pos1.y, pos1.z);
		this._shadowLight.decay  = 2.0;
		this._shadowLight.castShadow = $('#shadowBoxId').is(':checked');
	    this._shadowLight.intensity  = 2.00000;
	    this._shadowLight.shadow.mapSize.width = 1024;
		this._shadowLight.shadow.mapSize.height = 1024;
		this._shadowLight.shadow.camera.near = 0.1;
		this._shadowLight.shadow.camera.far = camera.far;
		this._shadowLight.shadow.camera.top = boundingDiogonal/2;
		this._shadowLight.shadow.camera.bottom = -boundingDiogonal/2;
		this._shadowLight.shadow.camera.left = -boundingDiogonal/2;
		this._shadowLight.shadow.camera.right = boundingDiogonal/2;
		this._shadowLight.shadow.bias = -0.0001;
	    this._scene.add(this._shadowLight);
		
	    this._defaultLight.visible = !this._shadowLight.castShadow; // we want this light to be off if the shadow light is turned on.
	}
	else
		return;
}

VWManager.prototype.SetDefaultLightPosition = function(inXPos, inYPos, worldDirection, width, height){
	var boundingDiogonal = this._boundMin.distanceTo(this._boundMax);
	var rotation = new THREE.Vector2(inXPos - width/2,height/2 - inYPos).normalize().angle();
	if(rotation >= 0 && rotation <= 3*Math.PI / 2)
	{
		rotation = rotation - Math.PI/2;
	}
	else
	{
		rotation = rotation - 5 * Math.PI / 2;
	}

	worldDirection.y = 0.0;
	worldDirection.normalize();
	worldDirection.applyAxisAngle(new THREE.Vector3(0,1,0), rotation);
	var distRatio = Math.sqrt((inXPos-50)*(inXPos-50) + (inYPos-50)*(inYPos-50)) / Math.sqrt(2*50*50);
	worldDirection.multiplyScalar(distRatio);
	var pos1 = worldDirection.multiplyScalar( boundingDiogonal );
	pos1.y = this._boundMax.y;
	this._shadowLight.position.set(pos1.x, pos1.y, pos1.z);
	
	this._renderAdaptor.render();
	return this._shadowLight.position.clone().normalize();
}